#: Wrangler asset upload progress lines — one per file, hundreds on large sites:
#:   "+ /index.html (1234 bytes)"
#:   "Uploading 42 assets to KV namespace ..."
#:   "Uploading asset /assets/logo.png (23456 bytes)"
_WRANGLER_ASSET_UPLOAD_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:\+\s+/\S+\s+\(\d+\s+bytes?\)|"
    r"Uploading\s+asset\s+/\S+|"
    r"Uploading\s+\d+\s+assets?\s+to\s+\S+|"
    r"No\s+cached\s+assets\s+found\.\s+Uploading\s+all\s+\d+|"
    r"Diff\s+result:\s+\d+\s+added|"
    r"↑\s+\S+\s+\(\d+\s+bytes?\))",
    re.IGNORECASE,
)
#: Wrangler "Skipping upload of asset" or "N assets already up to date" lines
_WRANGLER_ASSET_SKIP_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Skipping\s+upload\s+of\s+asset\s+|"
    r"\d+\s+assets?\s+(?:already\s+(?:up\s+to\s+date|uploaded)|unchanged)|"
    r"All\s+\d+\s+assets?\s+are\s+already\s+up\s+to\s+date)",
    re.IGNORECASE,
)
#: Wrangler build/bundle step noise:
#:   "Building..."
#:   "Bundling with esbuild..."
#:   "Checking for common issues..."
_WRANGLER_BUILD_STEP_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Building\.\.\.|"
    r"Bundling\s+with\s+esbuild|"
    r"Checking\s+for\s+common\s+issues|"
    r"Running\s+custom\s+build|"
    r"Processing\s+dependencies|"
    r"Minif(?:ying|ied)\s+|"
    r"Wrote\s+script\s+to\s+\S+\.js\b)",
    re.IGNORECASE,
)
#: Wrangler deploy/publish success and summary lines (always keep):
#:   "Published my-worker (0.25 sec)"
#:   "Deployed my-worker triggers: (routes)"
#:   "✨  Built successfully"
#:   "Total Upload: 42.3 KiB / gzip: 14.1 KiB"
#:   "Current Deployment ID: abc123"
#:   "Uploaded my-worker (0.5 sec)"
#:   "Your worker has access to the following bindings:"
_WRANGLER_SUMMARY_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Published\s+\S+\s+\(|"
    r"Deployed\s+\S+|"
    r"Uploaded\s+\S+\s+\(|"
    r"Total\s+Upload:|"
    r"Current\s+Deployment\s+ID:|"
    r"✨\s+Built\s+successfully|"
    r"Your\s+worker\s+has\s+access|"
    r"\d+\s+requests?\s+were\s+served|"
    r"View\s+your\s+(?:worker|pages\s+site)\s+at\b|"
    r"Success!?\s*$|"
    r"Deployment\s+(?:complete|ready)|"
    r"pages\.dev|"
    r"workers\.dev)",
    re.IGNORECASE,
)
#: Wrangler "Your worker has access to the following bindings:" detail lines:
#:   "- KV Namespaces:"
#:   "  - MY_KV: kv_namespace_id_abc"
_WRANGLER_BINDING_DETAIL_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s+- \w+\s*(?:Namespaces?|Buckets?|Databases?|Variables?):",
    re.IGNORECASE,
)
#: Wrangler tail / dev session noise lines:
#:   "[wrangler:inf] Ready on http://localhost:8787"
#:   "[mf:inf] Worker reloaded! (123ms)"
#:   "[mf:inf] Reloading..."
_WRANGLER_DEV_NOISE_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*\[(?:wrangler|mf):\w+\]\s+(?:Reloading\b|Worker\s+reloaded!|"
    r"GET\s+|POST\s+|PUT\s+|PATCH\s+|DELETE\s+|OPTIONS\s+|HEAD\s+)",
    re.IGNORECASE,
)
#: Wrangler KV / D1 / R2 bulk operation progress:
#:   "Inserting 500 rows..."
#:   "Processing chunk 1/10..."
_WRANGLER_BULK_PROGRESS_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Inserting\s+\d+\s+rows|"
    r"Processing\s+chunk\s+\d+/\d+|"
    r"Writing\s+\d+\s+key[s/])",
    re.IGNORECASE,
)


class WranglerFilter(Filter):
    """Compress Cloudflare ``wrangler deploy`` / ``publish`` / ``pages`` output.

    Wrangler emits one line per asset upload (can be hundreds for a Pages site),
    verbose esbuild bundling steps, and deployment event chatter.  The actual
    signal is the final "Published/Deployed" summary line and any errors.

    Compression model:

    * **Asset upload lines** (``+ /file.html (N bytes)``, ``Uploading asset``):
      collapsed to a count.
    * **Asset-skip lines** (``N assets already up to date``): collapsed to a
      count.
    * **Build step noise** (``Building...``, ``Bundling with esbuild``): dropped.
    * **Dev-mode noise** (``[wrangler:inf] Reloading...``, HTTP access lines):
      dropped.
    * **Bulk-operation progress** (``Processing chunk N/M``): collapsed.
    * **Summary / success lines** (``Published``, ``Deployed``, ``Total Upload``):
      always kept.
    * **Error lines**: always kept.
    * **Errors** (exit_code != 0): preserve all stderr unchanged.
    """
    error_passthrough = True

    name = "wrangler"
    binaries = frozenset(["wrangler", "wrangler2"])

    def _compress_body(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        combined = self._combine_output(stdout, stderr)
        lines = combined.split("\n")
        kept: list[str] = []
        upload_count = 0
        skip_count = 0
        dropped_build = 0
        dropped_dev = 0
        bulk_count = 0

        for line in lines:
            # Error signals and summary lines — always keep.
            if _ERROR_SIGNAL_RE.search(line) or _WRANGLER_SUMMARY_RE.match(line):
                kept.append(line)
                continue
            # Asset upload lines — count.
            if _WRANGLER_ASSET_UPLOAD_RE.match(line):
                upload_count += 1
                continue
            # Asset-skip lines — count.
            if _WRANGLER_ASSET_SKIP_RE.match(line):
                skip_count += 1
                continue
            # Build step noise — drop.
            if _WRANGLER_BUILD_STEP_RE.match(line):
                dropped_build += 1
                continue
            # Dev-mode HTTP access / reload noise — drop.
            if _WRANGLER_DEV_NOISE_RE.match(line):
                dropped_dev += 1
                continue
            # Bulk operation progress — count.
            if _WRANGLER_BULK_PROGRESS_RE.match(line):
                bulk_count += 1
                continue
            kept.append(line)

        out: list[str] = []
        if upload_count:
            out.append(
                f"[token-goat: {upload_count} asset upload line(s) collapsed; "
                f"disable via TOKEN_GOAT_BASH_COMPRESS for full list]"
            )
        if skip_count:
            out.append(
                f"[token-goat: {skip_count} asset-skip line(s) collapsed]"
            )
        if bulk_count:
            out.append(
                f"[token-goat: {bulk_count} bulk-operation progress line(s) collapsed]"
            )
        out.extend(kept)

        notes: list[str] = []
        _maybe_note(notes, dropped_build, f"dropped {dropped_build} build-step noise line(s)")
        _maybe_note(notes, dropped_dev, f"dropped {dropped_dev} dev-mode noise line(s)")
        self._emit_notes(out, notes)
        return self._finalize(out)


# ---------------------------------------------------------------------------
# Hardhat Ethereum development framework
# ---------------------------------------------------------------------------

#: Hardhat compilation step: "Compiling X files with Solc 0.8.24"
_HARDHAT_COMPILING_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*Compiling\s+\d+\s+(?:file[s]?\s+with|Solidity\s+file[s]?)",
    re.IGNORECASE,
)
#: Hardhat "Solc ... finished in Ns" per-compiler-version progress
_HARDHAT_SOLC_FINISHED_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*Solc\s+\S+\s+finished\s+in\s+\d",
    re.IGNORECASE,
)
#: Hardhat deployment transaction receipt noise:
#:   "deployer: 0xabc..."
#:   "Deployment transaction: 0xdef..."
#:   "Gas used: 1234567"
_HARDHAT_TX_NOISE_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:deployer:|"
    r"Deployment\s+transaction:|"
    r"Gas\s+used:\s+\d|"
    r"Transaction\s+hash:\s+0x|"
    r"Block\s+(?:number|hash):|"
    r"Nonce:\s+\d|"
    r"Value:\s+\d|"
    r"From:\s+0x|"
    r"To:\s+0x|"
    r"Contract\s+address:\s+0x\w{40}\s*$)",
    re.IGNORECASE,
)
#: Hardhat test framework output — passing test lines:
#:   "    ✓ should transfer tokens (45ms)"
#:   "    ✔ deploys successfully"
_HARDHAT_PASS_TEST_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s+(?:✓|✔|√)\s+",
)
#: Hardhat test summary (always keep):
#:   "N passing (2s)"
#:   "N pending"
#:   "N failing"
_HARDHAT_TEST_SUMMARY_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*\d+\s+(?:passing|failing|pending)\b",
    re.IGNORECASE,
)
#: Hardhat failure block header (always keep):
#:   "N failing"
#:   "AssertionError: ..."
_HARDHAT_FAILURE_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:\d+\s+failing\b|AssertionError:|Error:|expected\s+)",
    re.IGNORECASE,
)
#: Hardhat "Compilation finished successfully" or "Nothing to compile"
_HARDHAT_COMPILE_DONE_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Compilation\s+finished\s+successfully|Nothing\s+to\s+compile|"
    r"Compiled\s+\d+\s+Solidity\s+file|No\s+need\s+to\s+generate\s+any\s+compiler)",
    re.IGNORECASE,
)
#: Hardhat warnings about compiler settings (keep — actionable):
#:   "HardhatError: HH..."
#:   "Warning: ..."
_HARDHAT_WARN_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:HardhatError:|HardhatWarning:|Warning:|ProviderError:|"
    r"Duplicate\s+definition\s+of\b)",
    re.IGNORECASE,
)
#: Hardhat network/deployment header lines (keep — high value):
#:   "Deploying MyContract..."
#:   "MyContract deployed to: 0x..."
#:   "Running scripts/deploy.ts"
_HARDHAT_DEPLOY_HEADER_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Deploying\s+\w|"
    r"\w[\w\s]*\s+deployed\s+to:\s+0x|"
    r"Running\s+\S+\.(?:ts|js)\b|"
    r"Network:\s+\w|"
    r"Deploying\s+contracts\s+with\s+the\s+account)",
    re.IGNORECASE,
)


class HardhatFilter(Filter):
    """Compress Hardhat Ethereum development framework output.

    ``npx hardhat compile`` can emit dozens of "Compiling N files with Solc
    0.8.x" lines (one per version combination).  ``npx hardhat test`` emits
    one line per passing test (often 100+), drowning out failures.  Deployment
    scripts emit verbose transaction receipts with gas, block number, and full
    address data.

    Compression model:

    * **Compilation step lines** (``Compiling N files with Solc``): collapsed
      to a count; ``Compilation finished successfully`` always kept.
    * **``Solc X finished in Ns``** per-version timing: collapsed to a count.
    * **Passing test lines** (``✓ / ✔ description``): collapsed to a count.
    * **Test summary** (``N passing``, ``N failing``): always kept.
    * **Failure blocks** (``N failing``, ``AssertionError``): always kept.
    * **Transaction receipt noise** (gas, block, nonce, addresses): dropped.
    * **Deployment header lines** (``Deploying X...``, ``X deployed to: 0x``):
      always kept.
    * **Warning / error lines**: always kept.
    * **Errors** (exit_code != 0): preserve all stderr unchanged.
    """
    error_passthrough = True

    name = "hardhat"
    binaries = frozenset(["hardhat"])

    def _compress_body(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        combined = self._combine_output(stdout, stderr)
        lines = combined.split("\n")
        kept: list[str] = []
        compiling_count = 0
        solc_timing_count = 0
        pass_count = 0
        tx_noise_count = 0

        for line in lines:
            # Error signals, warnings, failure headers — always keep.
            if (
                _ERROR_SIGNAL_RE.search(line)
                or _HARDHAT_FAILURE_RE.match(line)
                or _HARDHAT_WARN_RE.match(line)
            ):
                kept.append(line)
                continue
            # Compilation done / deploy header / test summary — always keep.
            if (
                _HARDHAT_COMPILE_DONE_RE.match(line)
                or _HARDHAT_DEPLOY_HEADER_RE.match(line)
                or _HARDHAT_TEST_SUMMARY_RE.match(line)
            ):
                kept.append(line)
                continue
            # Compiling step lines — count.
            if _HARDHAT_COMPILING_RE.match(line):
                compiling_count += 1
                continue
            # Solc per-version timing — count.
            if _HARDHAT_SOLC_FINISHED_RE.match(line):
                solc_timing_count += 1
                continue
            # Passing test lines — count.
            if _HARDHAT_PASS_TEST_RE.match(line):
                pass_count += 1
                continue
            # Transaction receipt noise — drop.
            if _HARDHAT_TX_NOISE_RE.match(line):
                tx_noise_count += 1
                continue
            kept.append(line)

        out: list[str] = []
        if compiling_count:
            out.append(
                f"[token-goat: collapsed {compiling_count} Solidity compilation step line(s); "
                f"disable via TOKEN_GOAT_BASH_COMPRESS for full output]"
            )
        if solc_timing_count:
            out.append(
                f"[token-goat: collapsed {solc_timing_count} Solc per-version timing line(s)]"
            )
        out.extend(kept)

        notes: list[str] = []
        _maybe_note(notes, pass_count, f"collapsed {pass_count} passing test line(s)")
        _maybe_note(notes, tx_noise_count, f"dropped {tx_noise_count} transaction receipt noise line(s)")
        self._emit_notes(out, notes)
        return self._finalize(out)


# ---------------------------------------------------------------------------
# Serverless Framework (serverless.com) deploy / info / invoke
# ---------------------------------------------------------------------------

#: Serverless "Serverless: Packaging service..." and step progress lines
_SLS_STEP_PROGRESS_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*Serverless:\s+(?:Packaging\s+service|"
    r"Excluding\s+development\s+dependencies|"
    r"Creating\s+Stack\.\.\.|"
    r"Checking\s+Stack\s+create\s+progress|"
    r"Stack\s+create\s+finished|"
    r"Uploading\s+CloudFormation\s+file\s+to\s+S3|"
    r"Uploading\s+artifacts|"
    r"Uploading\s+service\s+\S+\.zip\s+file\s+to\s+S3|"
    r"Validating\s+template|"
    r"Updating\s+Stack\.\.\.|"
    r"Checking\s+Stack\s+update\s+progress|"
    r"Stack\s+update\s+finished|"
    r"Executing\s+Changeset|"
    r"Removing\s+old\s+service\s+artifacts\s+from\s+S3)",
    re.IGNORECASE,
)
#: Serverless CloudFormation stack event lines — IN_PROGRESS (drop) and
#: COMPLETE/FAILED (keep).  One CF event per resource per status transition.
_SLS_CF_IN_PROGRESS_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:AWS::|ServerlessDeployment).*_IN_PROGRESS\s*$|"
    r"^\s+\w+_IN_PROGRESS\s+(?:AWS::|ServerlessDeployment)",
)
_SLS_CF_COMPLETE_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:AWS::|ServerlessDeployment).*_COMPLETE\s*$|"
    r"^\s+(?:CREATE|UPDATE|DELETE|REPLACE|ROLLBACK)_COMPLETE\s+",
)
_SLS_CF_FAILED_RE: Final[re.Pattern[str]] = re.compile(
    r"\w+_FAILED\s+",
)
#: Serverless "Service Information" section header and endpoint/function lines
#: — always keep (these are the useful output).
_SLS_SERVICE_INFO_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Service\s+Information|service:\s+\S|stage:\s+\S|region:\s+\S|"
    r"stack:\s+\S|resources:|api\s+keys:|endpoints:|functions:|layers:|"
    r"ANY\s+-\s+https://|GET\s+-\s+https://|POST\s+-\s+https://|"
    r"PUT\s+-\s+https://|DELETE\s+-\s+https://|"
    r"Serverless:\s+Stack\s+Tags|"
    r"Serverless:\s+Invoke\s+|"
    r"Serverless:\s+(?:Done!|WARNING:|ERROR:))",
    re.IGNORECASE,
)
#: Serverless final deploy summary (always keep):
#:   "Service deployed to stack my-service-dev (42s)"
#:   "✔ Service deployed"
#:   "Serverless: Run the 'serverless info' command"
_SLS_SUMMARY_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Service\s+deployed\s+to\s+stack\s+|"
    r"✔\s+Service\s+deployed|"
    r"Serverless:\s+Run\s+the\s+'serverless|"
    r"Deployed\s+functions:|"
    r"Stack\s+Outputs\b)",
    re.IGNORECASE,
)
#: Serverless dotted progress / "." dot lines emitted during CF polling
_SLS_DOT_PROGRESS_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*\.+\s*$"
)
#: Serverless "Serverless: ......." tick lines during polling
_SLS_TICK_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*Serverless:\s+\.+\s*$"
)


class ServerlessFilter(Filter):
    """Compress Serverless Framework ``deploy`` / ``info`` / ``invoke`` output.

    The Serverless Framework CLI emits verbose CloudFormation stack event lines
    (one per resource per status transition), upload step announcements, and
    polling dots during the CF change-set execution.  On a service with 20+
    Lambda functions and associated IAM roles / log groups, a deploy generates
    100-300 lines; the actual signal is the endpoint URLs and final summary.

    Compression model:

    * **Step progress lines** (``Serverless: Packaging service...``):
      collapsed to a count.
    * **CF ``_IN_PROGRESS`` event lines**: dropped — completion events carry
      the same information.
    * **CF ``_COMPLETE`` event lines**: always kept.
    * **CF ``_FAILED`` event lines**: always kept.
    * **Service information section** (endpoints, function names): always kept.
    * **Final summary** (``Service deployed to stack ...``): always kept.
    * **Dot / tick progress** (``....``, ``Serverless: ....``): dropped.
    * **Error lines**: always kept.
    * **Errors** (exit_code != 0): preserve all stderr unchanged.
    """
    error_passthrough = True

    name = "serverless"
    binaries = frozenset(["serverless", "sls"])

    def _compress_body(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        combined = self._combine_output(stdout, stderr)
        lines = combined.split("\n")
        kept: list[str] = []
        step_count = 0
        in_progress_count = 0
        dot_count = 0

        for line in lines:
            # Error signals and CF failure events — always keep.
            if _ERROR_SIGNAL_RE.search(line) or _SLS_CF_FAILED_RE.search(line):
                kept.append(line)
                continue
            # Service info / summary lines — always keep.
            if (
                _SLS_SERVICE_INFO_RE.match(line)
                or _SLS_SUMMARY_RE.match(line)
                or _SLS_CF_COMPLETE_RE.match(line)
            ):
                kept.append(line)
                continue
            # Step progress lines — count.
            if _SLS_STEP_PROGRESS_RE.match(line):
                step_count += 1
                continue
            # CF IN_PROGRESS event lines — drop.
            if _SLS_CF_IN_PROGRESS_RE.match(line):
                in_progress_count += 1
                continue
            # Dot / tick progress — drop.
            if _SLS_DOT_PROGRESS_RE.match(line) or _SLS_TICK_RE.match(line):
                dot_count += 1
                continue
            kept.append(line)

        out: list[str] = []
        if step_count:
            out.append(
                f"[token-goat: collapsed {step_count} Serverless deploy step line(s); "
                f"disable via TOKEN_GOAT_BASH_COMPRESS for full output]"
            )
        out.extend(kept)

        notes: list[str] = []
        _maybe_note(notes, in_progress_count, f"dropped {in_progress_count} CF _IN_PROGRESS event line(s)")
        _maybe_note(notes, dot_count, f"dropped {dot_count} polling dot line(s)")
        self._emit_notes(out, notes)
        return self._finalize(out)


# ---------------------------------------------------------------------------
# Public registry & dispatch
# ---------------------------------------------------------------------------

#: Ordered registry of built-in filters.  First match wins, so more-specific
#: filters (named binaries) precede the generic fallback.  Users can append
#: their own :class:`Filter` subclasses but cannot redefine built-ins.
# ---------------------------------------------------------------------------
# Erlang/OTP — rebar3 compile, eunit, common_test
# ---------------------------------------------------------------------------

#: rebar3 "Compiling src/foo.erl" per-file progress line
_REBAR3_COMPILING_RE: Final[re.Pattern[str]] = re.compile(
    r"^==>\s+\S+\s+\(compile\)|"
    r"^Compiling\s+\S+\.erl\b",
    re.IGNORECASE,
)
#: rebar3 dependency-fetch progress: "Fetching foo 1.2.3" / "Already up-to-date"
_REBAR3_FETCH_RE: Final[re.Pattern[str]] = re.compile(
    r"^(?:Fetching|Downloading|Resolving|Locking)\s+\S|"
    r"^\s*Already\s+up-to-date\b|"
    r"^\s*All\s+dependencies\s+already\s+locked\b",
    re.IGNORECASE,
)
#: rebar3 "===> Verifying dependencies" / "===> Analyzing applications" noise
_REBAR3_STEP_NOISE_RE: Final[re.Pattern[str]] = re.compile(
    r"^===>\s+(?:Verifying\s+dependencies|Analyzing\s+applications|"
    r"Building\s+rebar3\b|Compiling\s+rebar3\b|"
    r"Using\s+locked\s+dependencies|"
    r"Updating\s+base\s+application\b)",
    re.IGNORECASE,
)
#: EUnit individual test pass: "  foo_tests:bar_test...ok"
_REBAR3_EUNIT_PASS_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s+\S+_tests?:\S+\.\.\.(ok|passed)\s*$",
    re.IGNORECASE,
)
#: Common Test "PASSED" test case lines
_REBAR3_CT_PASS_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s+(?:tc_passed|PASSED|ok)\s+\S+\s*$|"
    r"^\s+\d+\s+tests?,\s+\d+\s+(?:passed|ok)\b",
    re.IGNORECASE,
)
#: rebar3 "===> Tests passed" / "===> N tests passed" summary (always keep)
_REBAR3_SUMMARY_RE: Final[re.Pattern[str]] = re.compile(
    r"^===>\s+(?:Tests?\s+passed|Done\.|Finished\.|"
    r"\d+\s+tests?\s+passed|All\s+\d+\s+tests?\s+passed)|"
    r"^\s*All\s+\d+\s+tests?\s+passed\b|"
    r"^\s*\d+\s+tests?,\s+\d+\s+(?:failed|errors?)\b|"
    r"Test\s+Summary\s*:.*passed\b",
    re.IGNORECASE,
)
#: rebar3 failure markers (always keep)
_REBAR3_FAILURE_RE: Final[re.Pattern[str]] = re.compile(
    r"^===>\s+(?:ERROR|FAILED|Test\s+Failed|Tests?\s+Failed)|"
    r"^\s*(?:FAILED|ERROR|failed|error)\s*$|"
    r"^\s*\*\*\*",
    re.IGNORECASE,
)


class ErlangFilter(Filter):
    """Compress ``rebar3`` Erlang/OTP build and test output.

    ``rebar3 compile`` emits one line per ``.erl`` source file compiled; a
    medium project with 50+ modules produces 50+ near-identical lines.
    ``rebar3 eunit`` and ``rebar3 ct`` emit one line per passing test case.

    Compression model:

    * **Per-file compilation lines** (``Compiling foo.erl``): collapsed to a
      count; the ``==> app (compile)`` step header is always kept.
    * **Dependency-fetch noise** (``Fetching``, ``Downloading``,
      ``Already up-to-date``): collapsed to a count.
    * **Step-noise lines** (``==> Verifying dependencies``,
      ``==> Analyzing applications``): dropped.
    * **EUnit/CT passing test lines**: collapsed to a count.
    * **Test summary / ``Tests passed`` lines**: always kept.
    * **Failure lines** and error blocks: always kept.
    * **Errors** (exit_code != 0): preserve all stderr unchanged.
    """
    error_passthrough = True

    name = "rebar3"
    binaries = frozenset(["rebar3", "rebar"])
    subcommands = frozenset([
        "compile", "test", "eunit", "ct", "cover", "dialyzer",
        "deps", "upgrade", "release", "escriptize", "shell",
        "clean", "xref", "check", "as",
    ])

    def _compress_body(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        combined = self._combine_output(stdout, stderr)
        lines = combined.split("\n")
        kept: list[str] = []
        compiling_count = 0
        fetch_count = 0
        pass_count = 0
        dropped_noise = 0

        for line in lines:
            # Error signals and failure markers — always keep.
            if _ERROR_SIGNAL_RE.search(line) or _REBAR3_FAILURE_RE.match(line):
                kept.append(line)
                continue
            # Summary lines — always keep.
            if _REBAR3_SUMMARY_RE.search(line):
                kept.append(line)
                continue
            # Per-file compilation lines — count.
            if _REBAR3_COMPILING_RE.match(line):
                compiling_count += 1
                continue
            # Dependency-fetch noise — count.
            if _REBAR3_FETCH_RE.match(line):
                fetch_count += 1
                continue
            # Step-noise lines — drop.
            if _REBAR3_STEP_NOISE_RE.match(line):
                dropped_noise += 1
                continue
            # EUnit/CT passing test lines — count.
            if _REBAR3_EUNIT_PASS_RE.match(line) or _REBAR3_CT_PASS_RE.match(line):
                pass_count += 1
                continue
            kept.append(line)

        out: list[str] = []
        if compiling_count:
            out.append(
                f"[token-goat: {compiling_count} .erl compilation line(s) collapsed; "
                f"disable via TOKEN_GOAT_BASH_COMPRESS for full output]"
            )
        if fetch_count:
            out.append(
                f"[token-goat: {fetch_count} dependency-fetch line(s) collapsed]"
            )
        out.extend(kept)

        notes: list[str] = []
        _maybe_note(notes, pass_count, f"collapsed {pass_count} passing test line(s)")
        _maybe_note(notes, dropped_noise, f"dropped {dropped_noise} rebar3 step-noise line(s)")
        self._emit_notes(out, notes)
        return self._finalize(out)


# ---------------------------------------------------------------------------
# Fly.io deployment CLI (fly / flyctl)
# ---------------------------------------------------------------------------

#: fly deploy "==> Releasing" step header (always keep)
_FLY_STEP_HEADER_RE: Final[re.Pattern[str]] = re.compile(
    r"^==>\s+(?:Releasing|Building|Creating|Validating|Updating|Destroying|Monitoring)",
    re.IGNORECASE,
)
#: fly deploy per-machine status/progress: "--> Waiting for machine X to start"
#: and "machine X is now in a started state" (keep 1st occurrence per machine id)
_FLY_MACHINE_WAIT_RE: Final[re.Pattern[str]] = re.compile(
    r"^(?:-->?\s+Waiting\s+for|"
    r"\s*Machine\s+[0-9a-zA-Z]+\s+is\s+now\s+in|"
    r"\s*\[[\s\d]+\]\s+Machine\s+[0-9a-zA-Z]+)",
    re.IGNORECASE,
)
#: fly build step noise: "Sending build context", "Step N/M :", "--->"
_FLY_BUILD_STEP_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Sending\s+build\s+context|"
    r"Step\s+\d+/\d+\s*:|"
    r"-{3}>\s*\w|"
    r"Successfully\s+built\s+[0-9a-f]{8,}|"  # short image id
    r"Successfully\s+tagged\s+\S+)",
    re.IGNORECASE,
)
#: fly deploy image layer progress: "#N DONE" / "transferring context"
_FLY_LAYER_PROGRESS_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*#\d+\s+(?:CACHED|DONE|sha256:|transferring)|"
    r"^\s*CACHED\s+\[",
    re.IGNORECASE,
)
#: fly deploy "Watch your deployment at https://fly.io/apps/..." (keep)
#: "Visit your newly deployed app at https://..." (keep)
_FLY_SUMMARY_RE: Final[re.Pattern[str]] = re.compile(
    r"(?:Watch\s+your\s+deployment|"
    r"Visit\s+your\s+newly\s+deployed|"
    r"Deployed\s+\S+\s+v\d|"
    r"v\d+\s+deployed\s+successfully|"
    r"Release\s+command\s+succeeded|"
    r"Monitoring\s+deployment\s+\(Ctrl-C)",
    re.IGNORECASE,
)
#: fly "Checking DNS configuration" and other polling dots (drop)
_FLY_POLLING_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Checking\s+DNS\s+configuration|"
    r"Waiting\s+for\s+IPv[46]|"
    r"The\s+above\s+IP\s+address\s+may\s+need)",
    re.IGNORECASE,
)


class FlyFilter(Filter):
    """Compress ``fly`` (flyctl) deployment and status output.

    ``fly deploy`` emits Docker build layers, per-machine wait messages,
    polling dots and DNS-check lines that dwarf the useful deploy summary.
    ``fly status`` emits a per-machine table that can have dozens of rows for
    apps with many instances.

    Compression model:

    * **Docker build step lines** (``Step N/M``, ``--->``, ``CACHED``,
      ``#N DONE``): collapsed to a count.
    * **Per-machine wait lines** (``Waiting for machine X``,
      ``Machine X is now in a started state``): collapsed to a count.
    * **DNS/polling noise** (``Checking DNS configuration``,
      ``Waiting for IPv6``): dropped.
    * **Step headers** (``==> Releasing``, ``==> Building``): always kept.
    * **Deploy summary** (``Deployed X v1``, ``Visit your …``): always kept.
    * **Error lines**: always kept.
    * **Errors** (exit_code != 0): preserve all stderr unchanged.
    """
    error_passthrough = True

    name = "fly"
    binaries = frozenset(["fly", "flyctl"])
    subcommands = frozenset([
        "deploy", "status", "apps", "machines", "logs", "scale",
        "secrets", "volumes", "regions", "releases", "info",
        "launch", "destroy", "resume", "suspend", "open",
    ])

    def _compress_body(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        combined = self._combine_output(stdout, stderr)
        lines = combined.split("\n")
        kept: list[str] = []
        build_step_count = 0
        machine_wait_count = 0
        dropped_noise = 0

        for line in lines:
            # Error signals — always keep.
            if _ERROR_SIGNAL_RE.search(line):
                kept.append(line)
                continue
            # Deploy summary and step headers — always keep.
            if _FLY_SUMMARY_RE.search(line) or _FLY_STEP_HEADER_RE.match(line):
                kept.append(line)
                continue
            # Docker build step noise — count.
            if _FLY_BUILD_STEP_RE.match(line) or _FLY_LAYER_PROGRESS_RE.match(line):
                build_step_count += 1
                continue
            # Per-machine wait lines — count.
            if _FLY_MACHINE_WAIT_RE.match(line):
                machine_wait_count += 1
                continue
            # DNS / polling noise — drop.
            if _FLY_POLLING_RE.match(line):
                dropped_noise += 1
                continue
            kept.append(line)

        out: list[str] = []
        if build_step_count:
            out.append(
                f"[token-goat: {build_step_count} Docker build step line(s) collapsed; "
                f"disable via TOKEN_GOAT_BASH_COMPRESS for full output]"
            )
        if machine_wait_count:
            out.append(
                f"[token-goat: {machine_wait_count} per-machine wait line(s) collapsed]"
            )
        out.extend(kept)

        notes: list[str] = []
        _maybe_note(notes, dropped_noise, f"dropped {dropped_noise} DNS/polling noise line(s)")
        self._emit_notes(out, notes)
        return self._finalize(out)


# ---------------------------------------------------------------------------
# Foundry / Forge — Solidity compile + test (forge build / forge test)
# ---------------------------------------------------------------------------

#: forge compile per-file progress: "Compiling N files with solc 0.8.24"
#: and "Solc 0.8.24 finished in 3.45s"
_FORGE_COMPILING_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*Compiling\s+\d+\s+(?:file[s]?\s+with|Solidity\s+file[s]?)|"
    r"^\s*Solc\s+\S+\s+finished\s+in\s+\d",
    re.IGNORECASE,
)
#: forge test passing test lines: "[PASS] testFoo() (gas: 12345)"
_FORGE_PASS_TEST_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*\[(?:PASS|OK)\]\s+\S+\s+\(gas:",
    re.IGNORECASE,
)
#: forge test suite header: "Running N tests for src/Foo.t.sol:FooTest"
#: Always keep — anchors the failure context.
_FORGE_SUITE_HEADER_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*Running\s+\d+\s+test[s]?\s+for\s+\S+",
    re.IGNORECASE,
)
#: forge test summary: "Test result: ok. N passed; 0 failed; 0 skipped;"
#: and "Suite result: ok. N passed; ..."
_FORGE_SUMMARY_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Test\s+result|Suite\s+result|Overall\s+result)\s*:",
    re.IGNORECASE,
)
#: forge compile done: "Compiler run successful" / "Nothing to compile"
_FORGE_COMPILE_DONE_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Compiler\s+run\s+successful|"
    r"Nothing\s+to\s+compile|"
    r"Compiled\s+\d+\s+Solidity\s+file[s]?)",
    re.IGNORECASE,
)
#: forge failure header: "[FAIL. Counterexample: ...]" / "[FAIL]"
_FORGE_FAILURE_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*\[(?:FAIL|ERROR)\]",
    re.IGNORECASE,
)
#: forge gas report table separator rows only: | ----- | ----- |
#: Pure separator rows (only pipes, dashes, and spaces) are cosmetic noise.
#: Header rows (| Function Name | … |) and data rows are always kept.
_FORGE_GAS_TABLE_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*\|[-\s|]+\|\s*$",   # separator row: | ----- | ----- |
)
#: forge "Ran N test suites" footer (always keep)
_FORGE_FOOTER_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*Ran\s+\d+\s+test\s+suite[s]?\s+in\s+\d",
    re.IGNORECASE,
)


class ForgeFilter(Filter):
    """Compress Foundry ``forge build`` / ``forge test`` output.

    Foundry emits one "Compiling N files with solc" line per compiler
    version, one "[PASS] testFoo() (gas: ...)" line per passing test, and
    verbose gas-report table separators — all of which dwarf any failures.

    Compression model:

    * **Compilation step lines** (``Compiling N files with solc``,
      ``Solc X finished in Ns``): collapsed to a count; ``Compiler run
      successful`` is always kept.
    * **Passing test lines** (``[PASS] / [OK]``): collapsed to a count.
    * **Gas-report table separator rows**: dropped (headers and data rows kept).
    * **Test suite headers** (``Running N tests for …``): always kept.
    * **Test summary** (``Test result: ok. N passed``): always kept.
    * **Failure lines** (``[FAIL]``, ``[ERROR]``): always kept.
    * **Error lines**: always kept.
    * **Errors** (exit_code != 0): preserve all stderr unchanged.
    """
    error_passthrough = True

    name = "forge"
    binaries = frozenset(["forge"])
    subcommands = frozenset([
        "build", "test", "script", "verify-contract", "flatten",
        "inspect", "coverage", "snapshot", "clean", "install",
        "update", "remove", "init", "compile",
    ])

    def _compress_body(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        combined = self._combine_output(stdout, stderr)
        lines = combined.split("\n")
        kept: list[str] = []
        compiling_count = 0
        pass_count = 0
        dropped_gas_sep = 0

        for line in lines:
            # Error signals and failure headers — always keep.
            if _ERROR_SIGNAL_RE.search(line) or _FORGE_FAILURE_RE.match(line):
                kept.append(line)
                continue
            # Compile-done / suite headers / summaries / footer — always keep.
            if (
                _FORGE_COMPILE_DONE_RE.match(line)
                or _FORGE_SUITE_HEADER_RE.match(line)
                or _FORGE_SUMMARY_RE.match(line)
                or _FORGE_FOOTER_RE.match(line)
            ):
                kept.append(line)
                continue
            # Compilation step lines — count.
            if _FORGE_COMPILING_RE.match(line):
                compiling_count += 1
                continue
            # Passing test lines — count.
            if _FORGE_PASS_TEST_RE.match(line):
                pass_count += 1
                continue
            # Gas-report table separator rows — drop (cosmetic noise).
            if _FORGE_GAS_TABLE_RE.match(line):
                dropped_gas_sep += 1
                continue
            kept.append(line)

        out: list[str] = []
        if compiling_count:
            out.append(
                f"[token-goat: {compiling_count} Solidity compilation step line(s) collapsed; "
                f"disable via TOKEN_GOAT_BASH_COMPRESS for full output]"
            )
        out.extend(kept)

        notes: list[str] = []
        _maybe_note(notes, pass_count, f"collapsed {pass_count} passing test line(s)")
        _maybe_note(notes, dropped_gas_sep, f"dropped {dropped_gas_sep} gas-report table separator row(s)")
        self._emit_notes(out, notes)
        return self._finalize(out)


# ---------------------------------------------------------------------------
# AI coding assistant CLI output filters
# ---------------------------------------------------------------------------
# These filters compress the verbose output of popular AI coding assistant
# CLIs: aider, gh copilot, gemini (Gemini CLI), and claude (Claude Code CLI).
# All four emit high-noise output (token counts, cost lines, progress spinners,
# and session metadata) that surrounds the small amount of signal (errors,
# diff summaries, and final answers) actually useful to the model.
# ---------------------------------------------------------------------------

# aider ─────────────────────────────────────────────────────────────────────
#: aider "applying edits" progress block: "Applying edits...", "Applied edit to …"
_AIDER_APPLYING_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Applying\s+edit(?:s)?(?:\s+to\s+\S+)?|Applied\s+edit\s+to\s+\S+)\s*\.{0,3}\s*$",
    re.IGNORECASE,
)
#: aider token usage line: "Tokens: 1234 sent, 567 received."
_AIDER_TOKENS_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*Tokens:\s+\d[\d,]*\s+sent,\s+\d[\d,]*\s+received",
    re.IGNORECASE,
)
#: aider cost line: "Cost: $0.0012 message, $0.0034 session."
_AIDER_COST_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*Cost:\s+\$[\d.]+\s+message,\s+\$[\d.]+\s+session",
    re.IGNORECASE,
)
#: aider repo-map / context-loading noise
_AIDER_REPOMAP_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Repo-map:|Added\s+\S+\s+to\s+the\s+chat|Removed\s+\S+\s+from\s+the\s+chat"
    r"|Loading\s+repo\s+map|Updating\s+repo\s+map"
    r"|Scanning\s+repo\s+contents"
    r"|Using\s+\d+\s+tokens\s+of\s+repo\s+map)",
    re.IGNORECASE,
)
#: aider "aider v1.x.x" version banner
_AIDER_BANNER_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*aider\s+v\d+\.\d+",
    re.IGNORECASE,
)
#: aider "Use ctrl-c" / "Run with --help" footer noise
_AIDER_FOOTER_NOISE_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Use\s+ctrl-c|Run\s+with\s+--help|You\s+can\s+skip\s+this|Tip:|Note:)",
    re.IGNORECASE,
)
#: aider diff/edit block start: "Applied edits to N file(s):" or "Diff:"
_AIDER_DIFF_HEADER_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Applied\s+edits?\s+to\s+\d+\s+file|Diff\s*:)",
    re.IGNORECASE,
)


class AiderFilter(Filter):
    """Compress ``aider`` terminal AI coding assistant output.

    ``aider`` emits verbose output for every AI edit session: token usage and
    cost per message, repo-map loading progress, "applying edits" spinners,
    version banners, and footer tips.  The useful content is the actual edit
    summary (diffs applied, errors, and warnings).

    Compression model:

    * **Token/cost lines** (``Tokens: … sent, … received.``, ``Cost: $…``):
      collapsed to a single summary line per session run.
    * **"Applying edits" progress lines**: collapsed to a count.
    * **Repo-map loading noise** (``Repo-map:``, ``Added … to the chat``,
      ``Loading repo map``, etc.): dropped.
    * **Version banner** (``aider v1.x.x``): dropped.
    * **Footer tips** (``Use ctrl-c``, ``Tip:``, ``Note:``): dropped.
    * **Diff headers and error lines**: always kept.
    * **Errors** (exit_code != 0): preserve all stderr unchanged.
    """
    error_passthrough = True

    name = "aider"
    binaries = frozenset(["aider"])
    subcommands: frozenset[str] = frozenset()  # aider has no subcommands

    def matches(self, argv: list[str]) -> bool:  # noqa: D102
        if not argv:
            return False
        p = Path(argv[0])
        return p.stem.lower() == "aider"

    def _compress_body(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        combined = self._combine_output(stdout, stderr)
        lines = combined.split("\n")
        kept: list[str] = []
        token_lines: list[str] = []
        cost_lines: list[str] = []
        applying_count = 0
        dropped_noise = 0

        for line in lines:
            # Error signals — always keep.
            if _ERROR_SIGNAL_RE.search(line):
                kept.append(line)
                continue
            # Token usage lines — accumulate for summary.
            if _AIDER_TOKENS_RE.match(line):
                token_lines.append(line.strip())
                continue
            # Cost lines — accumulate for summary.
            if _AIDER_COST_RE.match(line):
                cost_lines.append(line.strip())
                continue
            # Applying edits progress — count.
            if _AIDER_APPLYING_RE.match(line):
                applying_count += 1
                continue
            # Repo-map noise — drop.
            if _AIDER_REPOMAP_RE.match(line):
                dropped_noise += 1
                continue
            # Version banner and footer tips — drop.
            if _AIDER_BANNER_RE.match(line) or _AIDER_FOOTER_NOISE_RE.match(line):
                dropped_noise += 1
                continue
            # Diff headers — always keep.
            if _AIDER_DIFF_HEADER_RE.match(line):
                kept.append(line)
                continue
            kept.append(line)

        out: list[str] = []
        if applying_count:
            out.append(
                f"[token-goat: {applying_count} 'applying edits' progress line(s) collapsed; "
                f"disable via TOKEN_GOAT_BASH_COMPRESS for full output]"
            )
        out.extend(kept)

        notes: list[str] = []
        if token_lines:
            # Emit last token usage line (most recent = current session total).
            notes.append(f"token usage: {token_lines[-1]}")
        if cost_lines:
            notes.append(f"cost: {cost_lines[-1]}")
        _maybe_note(notes, dropped_noise, f"dropped {dropped_noise} noise line(s)")
        self._emit_notes(out, notes)
        return self._finalize(out)


# gh copilot ─────────────────────────────────────────────────────────────────
#: gh copilot "Explanation:" section header
_GH_COPILOT_EXPLAIN_HDR_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Explanation\s*:|Welcome to GitHub Copilot)",
    re.IGNORECASE,
)
#: gh copilot disclaimer / legal lines
_GH_COPILOT_DISCLAIMER_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Disclaimer:|This response was|GitHub Copilot|The commands?\s+(?:above|below)|"
    r"Please review|Always review|Remember to|Note:|Tip:)",
    re.IGNORECASE,
)
#: gh copilot spinner/progress lines
_GH_COPILOT_SPINNER_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Asking GitHub Copilot|Generating|Thinking|Fetching)\s*\.{0,3}\s*$",
    re.IGNORECASE,
)
#: gh copilot / standalone copilot banner lines
#: Matches "Welcome to GitHub Copilot in the CLI", "Using GitHub Copilot",
#: "Authenticated as: …", and the standalone binary's "GitHub Copilot v1.x.x" line.
_GH_COPILOT_BANNER_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Welcome to GitHub Copilot|Using GitHub Copilot|Authenticated as|GitHub Copilot\s+v\d+)",
    re.IGNORECASE,
)


class GhCopilotFilter(Filter):
    """Compress ``gh copilot explain`` and ``gh copilot suggest`` output.

    GitHub Copilot CLI wraps its answers in verbose boilerplate: spinner lines,
    welcome banners, legal disclaimers, and "review this carefully" footers that
    dwarf the actual suggestion or explanation.

    Compression model:

    * **Spinner / progress lines** (``Asking GitHub Copilot…``,
      ``Generating…``): dropped.
    * **Welcome/auth banners** (``Welcome to GitHub Copilot in the CLI``,
      ``Authenticated as …``): dropped.
    * **Disclaimer / review footers** (``Disclaimer:``, ``Always review``,
      ``Note:``, ``Tip:``): dropped.
    * **The actual explanation or suggestion body**: always kept verbatim.
    * **Error lines**: always kept.
    * **Errors** (exit_code != 0): preserve all stderr unchanged.
    """
    error_passthrough = True

    name = "gh-copilot"
    binaries = frozenset(["gh"])

    def matches(self, argv: list[str]) -> bool:  # noqa: D102
        if not argv:
            return False
        p = Path(argv[0].replace("\\", "/"))
        stem = p.stem.lower()
        name = p.name.lower()
        if stem != "gh" and name != "gh":
            return False
        positionals = _positional_args(argv[1:])
        # Must be ``gh copilot explain`` or ``gh copilot suggest``.
        return (
            len(positionals) >= 2
            and positionals[0] == "copilot"
            and positionals[1] in {"explain", "suggest"}
        )

    def _compress_body(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        combined = self._combine_output(stdout, stderr)
        lines = combined.split("\n")
        kept: list[str] = []
        dropped_noise = 0

        for line in lines:
            # Error signals — always keep.
            if _ERROR_SIGNAL_RE.search(line):
                kept.append(line)
                continue
            # Spinner / progress lines — drop.
            if _GH_COPILOT_SPINNER_RE.match(line):
                dropped_noise += 1
                continue
            # Welcome/auth banners — drop.
            if _GH_COPILOT_BANNER_RE.match(line):
                dropped_noise += 1
                continue
            # Disclaimer/review footers — drop.
            if _GH_COPILOT_DISCLAIMER_RE.match(line):
                dropped_noise += 1
                continue
            kept.append(line)

        notes: list[str] = []
        _maybe_note(notes, dropped_noise, f"dropped {dropped_noise} boilerplate/disclaimer line(s)")
        self._emit_notes(kept, notes)
        return self._finalize(kept)


#: copilot workspace mode startup/loading noise lines
_COPILOT_WORKSPACE_NOISE_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Starting\s+Copilot\s+workspace|Loading\s+model:|Copilot\s+workspace\s+(?:starting|loaded|ready)|"
    r"Streaming\.\.\.|▌\s*$|Turn\s+\d+\s*:)",
    re.IGNORECASE,
)
#: copilot workspace mode completion/prompt token stats
_COPILOT_COMPLETION_STATS_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:Completion\s+tokens:|Prompt\s+tokens:|Total\s+tokens:|Input\s+tokens:|Output\s+tokens:)\s*\d",
    re.IGNORECASE,
)


class CopilotFilter(Filter):
    """Compress output from the standalone ``copilot`` binary.

    The standalone ``copilot`` binary (``npm i -g @githubnext/github-copilot-cli``)
    produces the same class of boilerplate as ``gh copilot`` but is invoked without
    the ``gh`` wrapper — e.g. ``copilot explain "git stash"`` or
    ``copilot workspace start``.

    Compression model (identical to :class:`GhCopilotFilter` plus workspace mode):

    * **Version/auth banners** (``GitHub Copilot v1.x.x``, ``Authenticated as …``):
      dropped.
    * **Spinner / progress lines** (``Generating…``, ``Thinking…``,
      ``Asking GitHub Copilot…``): dropped.
    * **Disclaimer / review footers** (``Disclaimer:``, ``Always review``,
      ``Note:``, ``Tip:``): dropped.
    * **Workspace startup noise** (``Starting Copilot workspace…``,
      ``Loading model: gpt-4o-mini…``, ``Turn 1:``, ``Streaming…``, cursor ``▌``):
      dropped.
    * **Completion stats** (``Completion tokens: …``, ``Prompt tokens: …``, etc.):
      kept as last-seen note (most recent value summarised).
    * **The actual explanation or suggestion body**: always kept verbatim.
    * **Errors** (exit_code != 0): preserve all output unchanged.

    Note: this filter intentionally does **not** match ``gh copilot …`` — that is
    handled by :class:`GhCopilotFilter`.  Only the stem ``copilot`` (without a
    ``gh`` prefix) is claimed here.
    """
    error_passthrough = True

    name = "copilot"
    binaries = frozenset(["copilot"])

    def matches(self, argv: list[str]) -> bool:  # noqa: D102
        if not argv:
            return False
        stem = Path(argv[0]).stem.lower()
        return stem == "copilot"

    def _compress_body(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        combined = self._combine_output(stdout, stderr)
        lines = combined.split("\n")
        kept: list[str] = []
        stat_lines: list[str] = []
        dropped_noise = 0

        for line in lines:
            # Error signals — always keep.
            if _ERROR_SIGNAL_RE.search(line):
                kept.append(line)
                continue
            # Workspace startup/loading noise — drop.
            if _COPILOT_WORKSPACE_NOISE_RE.match(line):
                dropped_noise += 1
                continue
            # Completion/prompt token stats — accumulate for summary note.
            if _COPILOT_COMPLETION_STATS_RE.match(line):
                stat_lines.append(line.strip())
                continue
            # Spinner / progress lines — drop.
            if _GH_COPILOT_SPINNER_RE.match(line):
                dropped_noise += 1
                continue
            # Version/auth banners — drop.
            if _GH_COPILOT_BANNER_RE.match(line):
                dropped_noise += 1
                continue
            # Disclaimer/review footers — drop.
            if _GH_COPILOT_DISCLAIMER_RE.match(line):
                dropped_noise += 1
                continue
            kept.append(line)

        notes: list[str] = []
        if stat_lines:
            notes.append(f"stats: {stat_lines[-1]}")
        _maybe_note(notes, dropped_noise, f"dropped {dropped_noise} boilerplate/disclaimer line(s)")
        self._emit_notes(kept, notes)
        return self._finalize(kept)


