        kept: list[str] = []
        dropped_noise = 0
        cascade_tool_count = 0
        last_context: str | None = None

        for line in lines:
            # Error signals — always keep.
            if _ERROR_SIGNAL_RE.search(line):
                kept.append(line)
                continue
            # Version banner — drop.
