#: Codex CLI version banner: "OpenAI Codex v0.137.0"
_CODEX_BANNER_RE: Final[re.Pattern[str]] = re.compile(
    r"^OpenAI Codex v\d+",
    re.IGNORECASE,
)
#: Codex separator line: "--------" (8+ dashes)
_CODEX_SEPARATOR_RE: Final[re.Pattern[str]] = re.compile(
    r"^-{4,}$",
)
#: Codex header config key=value: "model: gpt-5.4-mini"
_CODEX_MODEL_RE: Final[re.Pattern[str]] = re.compile(
    r"^model\s*:\s*(?P<model>\S+)",
    re.IGNORECASE,
)
#: Codex token count footer: "tokens used" label (next line holds the count)
_CODEX_TOKENS_USED_RE: Final[re.Pattern[str]] = re.compile(
    r"^tokens used$",
    re.IGNORECASE,
)
#: Codex role label lines: exactly "user" or "codex" on their own line
_CODEX_ROLE_RE: Final[re.Pattern[str]] = re.compile(
    r"^(?:user|codex)$",
    re.IGNORECASE,
)


class CodexExecFilter(Filter):
    """Compress codex (OpenAI Codex CLI) command output.

    The Codex CLI emits a verbose header block on every invocation: a version
    banner, a separator line, a block of session config (workdir, model,
    provider, approval, sandbox, reasoning settings, session id), a second
    separator, and then a multi-turn conversation transcript (user / prompt
    / codex / answer) followed by a tokens used footer.

    Only the substantive AI answer is useful in model context; everything else
    is noise.

    Compression model:

    * **Header block** (version banner, config lines, separators): dropped,
      replaced by a one-line summary [codex: model=<model>, tokens=<N>].
    * **Prompt / user turn**: dropped (the caller already has the prompt).
    * **AI answer** (content after the final codex role label and before
      tokens used): kept verbatim.
    * **Token footer** (tokens used / <count>): folded into the summary.
    * **Unrecognised format** (no banner, no separator, or no role labels):
      returned unchanged so no content is lost.
    * **Errors** (exit_code != 0): preserve all stderr unchanged.
    """
    error_passthrough = True

    name = "codex-exec"
    binaries = frozenset(["codex"])
    subcommands: frozenset[str] = frozenset()

    def matches(self, argv: list[str]) -> bool:  # noqa: D102
        if not argv:
            return False
        p = Path(argv[0])
        return p.stem.lower() == "codex"

    def _compress_body(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        combined = self._combine_output(stdout, stderr)
        if not combined.strip():
            return combined

        lines = combined.split("\n")

        first_sep_idx: int | None = None
        second_sep_idx: int | None = None
        for i, ln in enumerate(lines[:20]):
            if _CODEX_SEPARATOR_RE.match(ln.strip()):
                if first_sep_idx is None:
                    first_sep_idx = i
                else:
                    second_sep_idx = i
                    break
        # Require both separators — without the full --------/config/--------
        # structure we cannot safely bound the transcript region.
        if second_sep_idx is None:
            return combined  # unrecognised format — passthrough

        # Extract model from the config block (between the two separators).
        # first_sep_idx is guaranteed set when second_sep_idx is set.
        assert first_sep_idx is not None
        model: str = "unknown"
        for ln in lines[first_sep_idx + 1:second_sep_idx]:
            m = _CODEX_MODEL_RE.match(ln.strip())
            if m:
                model = m.group("model")
                break

        # Find the last "codex" role label restricted to the transcript region
        # (after the second separator).  Constraining the scan prevents answer
        # content that happens to be the bare word "codex" from being mistaken
        # for a role marker and truncating the extracted answer.
        last_codex_idx: int | None = None
        for i in range(second_sep_idx + 1, len(lines)):
            if lines[i].strip().casefold() == "codex":
                last_codex_idx = i

        if last_codex_idx is None:
            # No "codex" role label found — unrecognised format, passthrough.
            return combined

        # Find "tokens used" by scanning backward from the end of output.
        # Codex always emits this footer in the last handful of lines;
        # scanning backward avoids truncating answers that contain the phrase.
        tokens_line_idx: int | None = None
        tokens_count: str = "?"
        search_floor = max(last_codex_idx + 1, len(lines) - 6)
        for i in range(len(lines) - 1, search_floor - 1, -1):
            if _CODEX_TOKENS_USED_RE.match(lines[i].strip()):
                tokens_line_idx = i
                # The count is on the very next non-blank line.
                for j in range(i + 1, min(i + 3, len(lines))):
                    candidate = lines[j].strip()
                    if candidate:
                        tokens_count = candidate
                        break
                break

        # Extract the answer body.
        answer_end = tokens_line_idx if tokens_line_idx is not None else len(lines)
        answer_lines = lines[last_codex_idx + 1:answer_end]

        # Strip leading/trailing blank lines from the answer.
        while answer_lines and not answer_lines[0].strip():
            answer_lines = answer_lines[1:]
        while answer_lines and not answer_lines[-1].strip():
            answer_lines = answer_lines[:-1]

        summary = f"[codex: model={model}, tokens={tokens_count}]"
        out: list[str] = [summary, *answer_lines]
        return self._finalize(out)


# --- Meson build system ---------------------------------------------------

#: meson setup: important header and project metadata lines — always keep
_MESON_KEEP_RE: Final[re.Pattern[str]] = re.compile(
    r"^(?:The Meson build system$"
    r"|Version:\s"
    r"|Source dir:\s"
    r"|Build dir:\s"
    r"|Build type:\s"
    r"|Project name:\s"
    r"|Project version:\s"
    r"|Build targets in project:\s"
    r"|(?:C|C\+\+|Fortran|Rust|D|Go) compiler for the host machine:\s)"
)
#: meson setup: indented compiler/toolchain detail lines — suppress
_MESON_COMPILER_DETAIL_RE: Final[re.Pattern[str]] = re.compile(
    r"^  (?:Compiler|ld|linker|libtool|ar|ranlib|objcopy|objdump|strip|dlltool)\b"
    r"|^    [a-z]"
)
#: meson setup: "Found ninja-X.Y.Z at /path" — suppress (not actionable)
_MESON_FOUND_TOOL_RE: Final[re.Pattern[str]] = re.compile(
    r"^Found (?:ninja|cmake|pkg-config)\b"
)
#: meson setup: dependency/header/program probe lines — suppress, count
_MESON_PROBE_RE: Final[re.Pattern[str]] = re.compile(
    r"^(?:Has (?:header|function|type|symbol|member)\s+'"
    r"|Dependency \S"
    r"|Program \S[^:]+found:"
    r"|Library \S)"
)
#: meson compile: "[N/M] Compiling ..." progress lines — suppress, count
_MESON_COMPILE_PROGRESS_RE: Final[re.Pattern[str]] = re.compile(
    r"^\[\s*\d+/\d+\] Compiling "
)
#: meson compile: "[N/M] Linking ..." — keep (significant link step)
_MESON_LINK_RE: Final[re.Pattern[str]] = re.compile(
    r"^\[\s*\d+/\d+\] Linking "
)


class MesonFilter(Filter):
    """Compress ``meson setup`` configuration and ``meson compile`` build output.

    Meson produces two kinds of verbose output:

    * **Setup phase** (``meson setup builddir``): emits compiler detection
      details, indented toolchain info, dependency probe lines, and a
      "Found ninja" line before reaching the project summary.  A typical
      project outputs 40-80 lines; only the project metadata matters.

    * **Compile phase** (``meson compile -C builddir``): emits one
      ``[N/M] Compiling ...`` line per translation unit.  A project with
      200 .cpp files produces 200 near-identical progress lines.

    Compression model:

    * **Setup phase**: keep project metadata (name, version, build dir, build
      type, compiler summary line); suppress indented compiler detail lines,
      dependency/header probe lines, and "Found ninja" lines; count and
      report suppressed probes.
    * **Compile phase**: suppress ``[N/M] Compiling`` progress lines (count);
      keep ``[N/M] Linking`` lines verbatim; keep the final summary.
    * **Errors and warnings**: always kept verbatim.
    * **Error exit** (exit_code != 0): preserve all output unchanged.
    """
    error_passthrough = True

    name = "meson"
    binaries = frozenset(["meson"])

    def matches(self, argv: list[str]) -> bool:  # noqa: D102
        def _base(s: str) -> str:
            return Path(s.replace("\\", "/")).stem.lower()

        if not argv:
            return False
        return _base(argv[0]) == "meson"

    def _compress_body(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        combined = self._combine_output(stdout, stderr)
        lines = combined.split("\n")
        kept: list[str] = []
        compile_count = 0
        probe_count = 0
        detail_count = 0

        for line in lines:
            # Always keep error/warning diagnostics.
            if _ERROR_SIGNAL_RE.search(line):
                kept.append(line)
                continue
            # Keep important setup metadata / summary lines.
            if _MESON_KEEP_RE.match(line):
                kept.append(line)
                continue
            # Compile phase: [N/M] Linking — keep verbatim.
            if _MESON_LINK_RE.match(line):
                kept.append(line)
                continue
            # Compile phase: [N/M] Compiling — count and suppress.
            if _MESON_COMPILE_PROGRESS_RE.match(line):
                compile_count += 1
                continue
            # Setup phase: indented compiler/toolchain detail lines — suppress.
            if _MESON_COMPILER_DETAIL_RE.match(line):
                detail_count += 1
                continue
            # Setup phase: dependency/probe lines — count and suppress.
            if _MESON_PROBE_RE.match(line):
                probe_count += 1
                continue
            # Setup phase: "Found ninja/cmake/pkg-config" — suppress.
            if _MESON_FOUND_TOOL_RE.match(line):
                continue
            kept.append(line)

        notes: list[str] = []
        _maybe_note(notes, compile_count, f"collapsed {compile_count} [N/M] Compiling progress lines")
        _maybe_note(notes, probe_count, f"collapsed {probe_count} dependency/probe check lines")
        _maybe_note(notes, detail_count, f"suppressed {detail_count} compiler toolchain detail lines")
        self._emit_notes(kept, notes)
        return self._finalize(kept)


# --- Playwright E2E test runner -------------------------------------------

_PW_PASS_RE: Final[re.Pattern[str]] = re.compile(r"^\s+[✓✔]\s")
_PW_DOWNLOAD_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(Downloading|Downloaded|Installing)\s+\w"
    r"|^\s*[\d.]+\s+[KMG]b\s+\[",
    re.IGNORECASE,
)


class PlaywrightFilter(Filter):
    """Compress ``playwright test`` / ``npx playwright test`` output.

    Playwright emits one result line per test-browser combination.  A large
    suite running across chromium, firefox, and webkit can produce thousands
    of lines for even a modest test suite.  Passed-test lines carry no
    diagnostic value; only failures and the final summary matter.

    Compression model:

    * **Suppressed**: ``✓`` / ``✔`` passed-test lines; browser download
      progress lines from ``playwright install`` (``Downloading Chromium
      ...``, ``111.2 Mb [====] 100%``).
    * **Kept**: ``✗`` / ``✘`` failed-test lines, error messages and stack
      traces, the ``Running N tests using N workers`` header, and summary
      lines (``N passed (Xs)``, ``N failed``).
    """

    name = "playwright"
    binaries = frozenset(["playwright"])

    _SUBCMDS: frozenset[str] = frozenset(
        ["test", "show-trace", "codegen", "screenshot", "pdf", "install"]
    )

    def matches(self, argv: list[str]) -> bool:  # noqa: D102
        def _base(s: str) -> str:
            return Path(s.replace("\\", "/")).stem.lower()

        if not argv:
            return False
        base = _base(argv[0])
        if base == "playwright":
            return not argv[1:] or argv[1].lower() in self._SUBCMDS
        if base in {"npx", "pnpx", "bunx"}:
            rest = [a for a in argv[1:] if not a.startswith("-")]
            if rest and _base(rest[0]) == "playwright":
                return not rest[1:] or rest[1].lower() in self._SUBCMDS
        return False

    def compress(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        lines = (stdout + stderr).splitlines(keepends=True)
        kept: list[str] = []
        suppressed = 0
        for line in lines:
            stripped = line.rstrip("\n")
            if _PW_PASS_RE.match(stripped):
                suppressed += 1
                continue
            if _PW_DOWNLOAD_RE.match(stripped):
                suppressed += 1
                continue
            kept.append(line)
        notes: list[str] = []
        _maybe_note(notes, suppressed, f"suppressed {suppressed} passed-test / install-progress lines")
        self._emit_notes(kept, notes)
        return self._finalize(kept)



# --- Cypress E2E test runner -----------------------------------------------

# Pure separator lines: 30+ horizontal-rule (U+2500) or equals characters.
_CY_SEPARATOR_RE: Final[re.Pattern[str]] = re.compile(r"^\s*[─=]{30,}\s*$")

# Section headers emitted by Cypress run
_CY_RUN_START_RE: Final[re.Pattern[str]] = re.compile(r"^\s*\(Run Starting\)\s*$")
_CY_RESULTS_RE: Final[re.Pattern[str]] = re.compile(r"^\s*\(Results\)\s*$")
_CY_VIDEO_RE: Final[re.Pattern[str]] = re.compile(r"^\s*\(Video\)\s*$")
_CY_RUN_FINISH_RE: Final[re.Pattern[str]] = re.compile(r"^\s*\(Run Finished\)\s*$")

# Box-drawing characters (Unicode U+2500 block): top/bottom borders, side bars
_CY_BOX_TOP_RE: Final[re.Pattern[str]] = re.compile(r"^\s*┌[─]+┐\s*$")
_CY_BOX_SIDE_RE: Final[re.Pattern[str]] = re.compile(r"^\s*│")
_CY_BOX_BOTTOM_RE: Final[re.Pattern[str]] = re.compile(r"^\s*└[─]+┘\s*$")

# Passing test line: indent + ✓/✔ unicode check mark + non-space content
_CY_PASS_TEST_RE: Final[re.Pattern[str]] = re.compile(r"^\s+[✓✔]\s+\S")


class CypressFilter(Filter):
    """Compress ``cypress run`` E2E test output.

    Cypress emits significant structural noise in CI: a banner box listing
    runtime metadata, per-spec separator lines, a per-spec Results box
    (redundant with the final summary), and a Video section with per-percent
    compression progress lines.  None of these carry diagnostic value when
    tests pass; when tests fail the error messages and stack traces are
    preserved verbatim.

    Compression model:

    * **Run Starting box** (after the ``(Run Starting)`` header): the
      bordered metadata table listing Cypress version, browser, Node version,
      and spec paths is suppressed entirely.
    * **Separator lines**: pure horizontal-rule lines composed of 30 or more
      ``─`` (U+2500) or ``=`` characters are cosmetic dividers, dropped
      unconditionally.
    * **Per-spec Results box** (after each ``(Results)`` header): a bordered
      table repeating per-spec pass/fail counts already in the final Run
      Finished summary.  Suppressed to avoid redundancy.
    * **Video section** (between ``(Video)`` and ``(Run Finished)``):
      progress lines are pure noise; the entire section is suppressed.
    * **Passing test lines** (``✓``/``✔`` prefix) when exit code is 0:
      suppressed to surface only the pass-count summaries.  Lines whose
      lowercased text contains ``error`` are kept regardless.

    **Always kept**: failing-test lines, error messages and stack traces,
    ``N passing (Xs)`` / ``N failing`` per-spec summaries,
    ``Running: specname (N of M)`` per-spec headers, describe-block names,
    and the entire Run Finished summary table.
    """

    name = "cypress"
    binaries = frozenset(["cypress"])

    _SUBCMDS: frozenset[str] = frozenset(["run", "open"])

    def matches(self, argv: list[str]) -> bool:  # noqa: D102
        def _base(s: str) -> str:
            return Path(s.replace("\\", "/")).stem.lower()

        if not argv:
            return False
        base = _base(argv[0])
        if base == "cypress":
            return not argv[1:] or argv[1].lower() in self._SUBCMDS
        if base in {"npx", "pnpx", "bunx"}:
            rest = [a for a in argv[1:] if not a.startswith("-")]
            if rest and _base(rest[0]) == "cypress":
                return not rest[1:] or rest[1].lower() in self._SUBCMDS
        return False

    def compress(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        lines = (stdout + stderr).splitlines(keepends=True)
        kept: list[str] = []

        # State machine: NORMAL | PRE_BOX | IN_BOX | IN_VIDEO | IN_SUMMARY
        state = "NORMAL"

        n_header = 0  # lines from Run Starting / Results boxes
        n_sep = 0     # separator lines
        n_video = 0   # video-section lines
        n_pass = 0    # passing test lines

        for line in lines:
            s = line.rstrip()

            if state == "IN_SUMMARY":
                kept.append(line)
                continue

            if state == "IN_VIDEO":
                if _CY_RUN_FINISH_RE.match(s):
                    state = "IN_SUMMARY"
                    kept.append(line)
                elif "error" in s.lower():
                    kept.append(line)
                else:
                    n_video += 1
                continue

            if state == "IN_BOX":
                if "error" not in s.lower():
                    n_header += 1
                    if _CY_BOX_BOTTOM_RE.match(s):
                        state = "NORMAL"
                else:
                    kept.append(line)
                    if _CY_BOX_BOTTOM_RE.match(s):
                        state = "NORMAL"
                continue

            if state == "PRE_BOX":
                if _CY_BOX_TOP_RE.match(s):
                    if "error" not in s.lower():
                        n_header += 1
                    else:
                        kept.append(line)
                    state = "IN_BOX"
                elif not s:
                    n_header += 1
                else:
                    kept.append(line)
                    state = "NORMAL"
                continue

            # NORMAL state
            if _CY_RUN_START_RE.match(s) or _CY_RESULTS_RE.match(s):
                if "error" not in s.lower():
                    n_header += 1
                    state = "PRE_BOX"
                else:
                    kept.append(line)
                continue

            if _CY_VIDEO_RE.match(s):
                if "error" not in s.lower():
                    n_video += 1
                    state = "IN_VIDEO"
                else:
                    kept.append(line)
                continue

            if _CY_RUN_FINISH_RE.match(s):
                state = "IN_SUMMARY"
                kept.append(line)
                continue

            if _CY_SEPARATOR_RE.match(s):
                if "error" not in s.lower():
                    n_sep += 1
                else:
                    kept.append(line)
                continue

            if exit_code == 0 and _CY_PASS_TEST_RE.match(s) and "error" not in s.lower():
                n_pass += 1
                continue

            kept.append(line)

        # EOF guard: if state machine is still in a non-NORMAL state, the
        # input was truncated (box/video section never closed). Emit a note
        # so the caller knows output may be incomplete.
        if state in ("IN_BOX", "PRE_BOX"):
            kept.append("[token-goat] warning: cypress output truncated inside header box")
        elif state == "IN_VIDEO":
            kept.append("[token-goat] warning: cypress output truncated inside video section")
        notes: list[str] = []
        _maybe_note(notes, n_header, f"suppressed {n_header} cypress header/results box lines")
        _maybe_note(notes, n_sep, f"suppressed {n_sep} separator lines")
        _maybe_note(notes, n_video, f"suppressed {n_video} video processing lines")
        _maybe_note(notes, n_pass, f"suppressed {n_pass} passing test lines")
        self._emit_notes(kept, notes)
        return self._finalize(kept)


# --- ffmpeg / ffprobe / ffplay -----------------------------------------------

# "ffmpeg version 6.0 Copyright …" / "ffprobe version 5.1.3 …"
_FFMPEG_VERSION_RE: Final[re.Pattern[str]] = re.compile(
    r"^ff(?:mpeg|probe|play)\s+version\s", re.IGNORECASE
)
# Build-info noise lines that appear in the header block:
#   "  built with Apple clang version 14.0.3 …"
#   "  configuration: --prefix=/usr/local/Cellar/ffmpeg/5.1.4 --enable-…"
#   "  libavutil      57. 28.100 / 57. 28.100"
#   "  libavcodec     59. 37.100 / 59. 37.100" (and libswscale, libpostproc, …)
_FFMPEG_BUILD_NOISE_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s+(?:built with\b|configuration:|lib(?:av|sw|post)\w+\s+\d)"
)
# "  Metadata:" or "    Metadata:" — section-header line with no key-value.
_FFMPEG_METADATA_SECTION_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s{2,}Metadata:\s*$"
)
# Metadata key-value lines indented ≥4 spaces with the format "key  : value" or "key: value".
# Matches:  "    major_brand     : isom"  "    compatible_brands: isomiso2avc1mp41"
# Does NOT match: "    Stream #0:0(und): Video: h264 …" (starts with "Stream #")
_FFMPEG_METADATA_KV_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s{4,}(?!Stream\s*#)[\w][\w ]*\s*:\s+"
)
# "Input #0, mov,mp4,m4a,3gp,3g2,mj2, from 'input.mp4':"
# "Output #0, matroska, to 'output.mkv':"
_FFMPEG_INPUT_OUTPUT_RE: Final[re.Pattern[str]] = re.compile(
    r"^(?:Input|Output)\s+#\d+,"
)
# "  Duration: 00:10:00.00, start: 0.000000, bitrate: 5000 kb/s"
_FFMPEG_DURATION_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s{2,}Duration:\s"
)
# "    Stream #0:0(und): Video: h264 (High), yuv420p, 1920x1080 …"
_FFMPEG_STREAM_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s{4,}Stream\s+#\d+:\d+"
)
# "Stream mapping:" section header
_FFMPEG_STREAM_MAPPING_RE: Final[re.Pattern[str]] = re.compile(
    r"^Stream mapping:\s*$"
)
# Real-time progress: "frame=  100 fps= 25 q=23.0 size=   512kB time=00:00:04.00 bitrate=…"
_FFMPEG_PROGRESS_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*frame=\s*\d+\s+fps="
)
# Final encoding-statistics line:
# "video:373440kB audio:1559kB subtitle:0kB other streams:0kB global headers:0kB muxing overhead: …"
_FFMPEG_FINAL_STATS_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*video:\d+kB\s+audio:\d+kB"
)
# "Press [q] to quit, or [?] for help" — interactive UI hint.
_FFMPEG_PRESS_Q_RE: Final[re.Pattern[str]] = re.compile(
    r"^Press\s+\[q\]\s+to\s+quit"
)


class FfmpegFilter(Filter):
    """Compress ``ffmpeg``, ``ffprobe``, and ``ffplay`` output.

    These tools emit a verbose header block (build configuration, library
    versions), per-stream metadata key-value pairs, and — when encoding — a
    continuously-overwriting progress line followed by a final stats summary.

    Compression model:

    * **Drop** the build-info block: ``built with``, ``configuration:`` and
      all ``lib*`` version lines (10–30 lines of noise on every invocation).
    * **Keep** the tool version line (e.g. ``ffmpeg version 6.0 …``).
    * **Keep** ``Input #N`` and ``Output #N`` container-format lines.
    * **Keep** ``Duration:`` and ``Stream #N:M`` codec/track lines — these
      describe the media essence and are the signal for diagnostic use.
    * **Drop** ``Metadata:`` section headers and their key-value sub-lines
      (``major_brand``, ``handler_name``, ``creation_time``, etc.).
    * **Drop** the ``Press [q] to quit`` interactivity hint.
    * **Collapse** ``frame=N fps=N …`` real-time progress lines to the last
      one seen (they are already collapsed by :func:`strip_progress` when the
      output is a TTY; when captured as plain text each frame is a separate
      line so can number in the thousands for long encodes).
    * **Keep** the final encoding-statistics line
      (``video:NkB audio:NkB … muxing overhead: …``).
    * **Always keep** error and warning diagnostic lines.
    """

    name = "ffmpeg"
    binaries = frozenset(["ffmpeg", "ffprobe", "ffplay"])

    def compress(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        # ffmpeg/ffprobe write all diagnostics to stderr; stdout carries muxed
        # binary media when writing to a pipe.  Use stderr as the primary text
        # stream and fall back to stdout only when stderr is empty.
        primary = stderr if stderr.strip() else stdout
        lines = primary.split("\n")

        kept: list[str] = []
        dropped_build = 0
        dropped_meta = 0
        dropped_progress = 0
        last_progress: str | None = None
        in_stream_mapping = False

        for line in lines:
            s = line.rstrip()

            # Always keep error / warning lines.
            lower = s.lower()
            if "error" in lower or "warning" in lower:
                kept.append(s)
                in_stream_mapping = False
                continue

            # Version header: "ffmpeg version 6.0 Copyright …"
            if _FFMPEG_VERSION_RE.match(s):
                kept.append(s)
                in_stream_mapping = False
                continue

            # Build-info block: "  built with …", "  configuration: …", "  libav… N"
            if _FFMPEG_BUILD_NOISE_RE.match(s):
                dropped_build += 1
                continue

            # Real-time progress: "frame=N fps=N q=… size=… time=… bitrate=…"
            if _FFMPEG_PROGRESS_RE.match(s):
                dropped_progress += 1
                last_progress = s
                in_stream_mapping = False
                continue

            # Final encoding stats: "video:NkB audio:NkB …"
            if _FFMPEG_FINAL_STATS_RE.match(s):
                if last_progress is not None:
                    kept.append(last_progress)
                    last_progress = None
                    dropped_progress -= 1  # re-added; not collapsed
                kept.append(s)
                in_stream_mapping = False
                continue

            # "Press [q] to quit, or [?] for help" — interactivity hint.
            if _FFMPEG_PRESS_Q_RE.match(s):
                dropped_meta += 1
                in_stream_mapping = False
                continue

            # "Stream mapping:" section header.
            if _FFMPEG_STREAM_MAPPING_RE.match(s):
                kept.append(s)
                in_stream_mapping = True
                continue

            # Stream mapping content: "  Stream #0:0 -> #0:0 (copy)"
            if in_stream_mapping and s.lstrip().startswith("Stream #"):
                kept.append(s)
                continue

            # "  Metadata:" or "    Metadata:" section header.
            if _FFMPEG_METADATA_SECTION_RE.match(s):
                dropped_meta += 1
                in_stream_mapping = False
                continue

            # Metadata key-value: "    major_brand     : isom"
            if _FFMPEG_METADATA_KV_RE.match(s):
                dropped_meta += 1
                continue

            # "Input #0, mov,mp4,…, from 'file':" / "Output #0, matroska, to 'file':"
            if _FFMPEG_INPUT_OUTPUT_RE.match(s):
                kept.append(s)
                in_stream_mapping = False
                continue

            # "  Duration: HH:MM:SS.ss, start: …, bitrate: … kb/s"
            if _FFMPEG_DURATION_RE.match(s):
                kept.append(s)
                continue

            # "    Stream #N:M(lang): Video/Audio/Subtitle: …"
            if _FFMPEG_STREAM_RE.match(s):
                kept.append(s)
                in_stream_mapping = False
                continue

            # Everything else: keep (unknown tool-specific messages, ffplay UI, etc.).
            kept.append(s)
            in_stream_mapping = False

        # If progress lines were suppressed but no final-stats line followed
        # (e.g. encoding was interrupted), surface the last progress frame.
        if last_progress is not None:
            kept.append(last_progress)
            dropped_progress -= 1  # re-added; not collapsed

        notes: list[str] = []
        _maybe_note(notes, dropped_build, f"dropped {dropped_build} build-info lines")
        _maybe_note(notes, dropped_meta, f"dropped {dropped_meta} metadata lines")
        _maybe_note(notes, dropped_progress, f"collapsed {dropped_progress} progress lines")
        self._emit_notes(kept, notes)
        return self._finalize(kept)


# --- Angular CLI (ng build / serve / test) -----------------------------------

#: Old webpack-based ng build: "chunk {0} polyfills.js (polyfills) 141 kB [initial] [rendered]"
_NG_WEBPACK_CHUNK_RE: Final[re.Pattern[str]] = re.compile(
    r"^chunk \{\d+\} "
)

#: New application-builder chunk data row: "main.abc123.js | main | 172 kB | 45 kB"
#: A non-whitespace filename with a JS/CSS extension followed by whitespace+pipe.
_NG_CHUNK_ROW_RE: Final[re.Pattern[str]] = re.compile(
    r"^\S+\.(?:js|css|mjs)\s+\|"
)

#: Table section header emitted by the new application builder (both capitalizations seen in the wild)
_NG_TABLE_HEADER_RE: Final[re.Pattern[str]] = re.compile(
    r"^(?:Initial [Cc]hunk [Ff]iles|Lazy [Cc]hunk [Ff]iles)\s+\|",
    re.IGNORECASE,
)

#: Build summary lines: "Build at: ..." (new builder) / "Date: ..." (old webpack)
_NG_BUILD_AT_RE: Final[re.Pattern[str]] = re.compile(
    r"^(?:Build at:|Date:)\s"
)

#: "Application bundle generation complete." / "✔ Browser application bundle generation complete."
_NG_BUNDLE_COMPLETE_RE: Final[re.Pattern[str]] = re.compile(
    r"(?:Browser application bundle|Application bundle) generation complete",
    re.IGNORECASE,
)

#: Build progress / spinner prefix lines to drop (they duplicate the summary)
_NG_BUILD_PROGRESS_RE: Final[re.Pattern[str]] = re.compile(
    r"^- (?:Generating|Building)\s"
    r"|^Building\.\.\.\s*$"
    r"|^Generating browser application bundles"
)

#: Budget warning lines emitted by ng build — always keep (these are actionable)
_NG_BUDGET_WARN_RE: Final[re.Pattern[str]] = re.compile(
    r"budget\s+exceeded|exceeded\s+(?:maximum\s+)?budget|Warning:\s+budget",
    re.IGNORECASE,
)

#: Karma / ng test: timestamped INFO/DEBUG/WARN log lines produced by Karma's logger
#: Example: "09 01 2024 10:30:00.123:INFO [karma]: Karma v6.4.2 server started …"
#: Also matches simpler "INFO [karma]: …" / "WARN [launcher]: …" formats.
_NG_KARMA_LOG_RE: Final[re.Pattern[str]] = re.compile(
    r"^\d{2} \d{2} \d{4} \d{2}:\d{2}:\d{2}[.:]\d{3}:(?:INFO|DEBUG|WARN)\s"
    r"|^(?:INFO|WARN)\s+\[(?:karma|launcher|karma-server|Chrome|Firefox|Safari)",
    re.IGNORECASE,
)

#: Karma per-browser result line: "Chrome Headless 120.0 … Executed 134 of 134 SUCCESS …"
_NG_KARMA_RESULT_RE: Final[re.Pattern[str]] = re.compile(
    r"(?:Chrome|Firefox|Safari|HeadlessChrome|ChromeHeadless)\s.*Executed\s+\d+\s+of\s+\d+",
    re.IGNORECASE,
)

#: Karma aggregate summary: "TOTAL: 134 SUCCESS" / "TOTAL: 2 FAILED"
_NG_KARMA_TOTAL_RE: Final[re.Pattern[str]] = re.compile(
    r"^TOTAL:\s+\d+\s+(?:SUCCESS|FAILED)",
    re.IGNORECASE,
)

#: Rows to keep at each end of a chunk table section before collapsing the middle.
_NG_TABLE_KEEP_EACH: Final[int] = 3


class NgFilter(Filter):
    """Compress Angular CLI (``ng``) build, serve, and test output.

    Angular's ``ng build`` emits a chunk-file table listing every generated
    JavaScript and CSS asset.  Large applications with many feature modules can
    produce 50+ lazy-chunk rows, all following the same
    ``filename | module-name | size | transfer-size`` pattern — pure noise
    when the build succeeds.  The legacy webpack-based builder emits
    ``chunk {N} …`` lines in the same fashion.

    ``ng test`` runs Karma and emits browser-connection log lines
    (timestamped ``INFO [karma]: …`` entries) that carry no signal.

    Compression model:

    * **Chunk file tables** (new application-builder format): keep the table
      header, keep the first :data:`_NG_TABLE_KEEP_EACH` and last
      :data:`_NG_TABLE_KEEP_EACH` data rows per section, collapse the middle
      to a count note.  Total/footer rows are always kept.
    * **Webpack chunk lines** (old builder ``chunk {N} …`` format): same
      head + tail keep, collapse middle.
    * **Budget warnings** (``Warning: budget exceeded …``): always kept.
    * **Build summary** (``Build at:`` / ``Date:`` / ``Application bundle
      generation complete.``): always kept.
    * **ng test / Karma log noise**: drop ``INFO [karma]`` / ``INFO
      [launcher]`` / browser-connection lines; keep test-result and
      ``TOTAL:`` lines.
    * **Error exit** (exit_code != 0): preserve all output unchanged.
    * **Short subcommands** (``generate``, ``add``, ``update``, ``lint``):
      light byte cap only; these are inherently brief.
    """
    error_passthrough = True

    name = "ng"
    binaries = frozenset(["ng"])

    def _compress_body(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        positionals = _positional_args(argv[1:])
        subcommand = positionals[0].lower() if positionals else ""

        combined = self._combine_output(stdout, stderr)
        lines = combined.split("\n")

        if subcommand == "test":
            return self._compress_test(lines)
        if subcommand in ("build", "serve", ""):
            return self._compress_build(lines)
        # Short subcommands (generate, add, update, lint, version, …)
        return cap_bytes(combined, 8_192)

    # ------------------------------------------------------------------
    # Subcommand helpers
    # ------------------------------------------------------------------

    def _compress_build(self, lines: list[str]) -> str:
        """Collapse chunk tables; preserve budget warnings and build summary."""
        kept: list[str] = []
        table_rows: list[str] = []   # buffered new-builder chunk rows for current section
        in_table = False
        webpack_run: list[str] = []  # buffered consecutive old-webpack chunk lines
        collapsed_rows = 0
        dropped_progress = 0

        def _flush_rows(rows: list[str], label: str) -> None:
            nonlocal collapsed_rows
            n = _NG_TABLE_KEEP_EACH
            if len(rows) <= n * 2:
                kept.extend(rows)
            else:
                kept.extend(rows[:n])
                mid_count = len(rows) - n * 2
                kept.append(f"[token-goat: collapsed {mid_count} {label}]")
                collapsed_rows += mid_count
                kept.extend(rows[-n:])

        for line in lines:
            # End an open webpack-chunk run when a non-chunk line appears.
            if webpack_run and not _NG_WEBPACK_CHUNK_RE.match(line):
                _flush_rows(webpack_run, "webpack chunk lines")
                webpack_run = []

            # End an open new-builder table section when a non-chunk-row appears.
            if in_table and not _NG_CHUNK_ROW_RE.match(line):
                _flush_rows(table_rows, "chunk table rows")
                table_rows = []
                in_table = False

            # Budget warnings — always keep.
            if _NG_BUDGET_WARN_RE.search(line):
                kept.append(line)
                continue

            # Error/warning diagnostics — always keep.
            if _ERROR_SIGNAL_RE.search(line):
                kept.append(line)
                continue

            # Build summary lines — always keep.
            if _NG_BUILD_AT_RE.match(line) or _NG_BUNDLE_COMPLETE_RE.search(line):
                kept.append(line)
                continue

            # Table section header (new application builder).
            if _NG_TABLE_HEADER_RE.match(line):
                kept.append(line)
                in_table = True
                table_rows = []
                continue

            # New-builder chunk data row (only accepted inside a table section).
            if in_table and _NG_CHUNK_ROW_RE.match(line):
                table_rows.append(line)
                continue

            # Old webpack chunk line — accumulate into a run.
            if _NG_WEBPACK_CHUNK_RE.match(line):
                webpack_run.append(line)
                continue

            # Build progress / spinner lines.
            if _NG_BUILD_PROGRESS_RE.match(line):
                dropped_progress += 1
                continue

            kept.append(line)

        # Flush any open runs at EOF.
        if webpack_run:
            _flush_rows(webpack_run, "webpack chunk lines")
        if in_table and table_rows:
            _flush_rows(table_rows, "chunk table rows")

        notes: list[str] = []
        _maybe_note(notes, dropped_progress, f"dropped {dropped_progress} build progress lines")
        self._emit_notes(kept, notes)
        return self._finalize(kept)

    def _compress_test(self, lines: list[str]) -> str:
        """Drop Karma info/debug log noise; keep test results and error lines."""
        kept: list[str] = []
        dropped_karma = 0

        for line in lines:
            # Karma per-browser result and TOTAL summary — always keep (checked
            # before noise drop because result lines can carry an INFO prefix).
            if _NG_KARMA_RESULT_RE.search(line) or _NG_KARMA_TOTAL_RE.match(line):
                kept.append(line)
                continue
            # Error/warning diagnostics — always keep.
            if _ERROR_SIGNAL_RE.search(line):
                kept.append(line)
                continue
            # Bundle-complete line (appears before Karma starts) — keep.
            if _NG_BUNDLE_COMPLETE_RE.search(line):
                kept.append(line)
                continue
            # Karma log noise — drop (after result/error guards above).
            if _NG_KARMA_LOG_RE.search(line):
                dropped_karma += 1
                continue
            kept.append(line)

        notes: list[str] = []
        _maybe_note(notes, dropped_karma, f"dropped {dropped_karma} Karma log lines")
        self._emit_notes(kept, notes)
        return self._finalize(kept)


# --- dotenv ----------------------------------------------------------------

#: python-dotenv / dotenv-cli diagnostics worth keeping verbatim — parse
#: failures are actionable, not banner noise.
_DOTENV_PARSE_WARN_RE: Final[re.Pattern[str]] = re.compile(
    r"python-dotenv|could not parse|failed to parse|parse error",
    re.IGNORECASE,
)
#: "Exported 23 variables" / "Loaded 23 variables" / "loaded 23 vars" count lines.
_DOTENV_EXPORT_COUNT_RE: Final[re.Pattern[str]] = re.compile(
    r"\b(?:Exported|Loaded|loaded)\s+(\d+)\s+var(?:iable)?s?\b",
    re.IGNORECASE,
)
#: "Skipped 2 variables (already set)" — collapse but never add to the tally.
_DOTENV_SKIPPED_RE: Final[re.Pattern[str]] = re.compile(
    r"\bSkipped\s+\d+\s+var(?:iable)?s?\b",
    re.IGNORECASE,
)
#: Count-less loading banners: "[dotenv] Loading .env", "Loading .env environment
#: variables...", "Loaded variables from .env".
_DOTENV_PLAIN_LOAD_RE: Final[re.Pattern[str]] = re.compile(
    r"(?:^|\s)\[dotenv\]\s+Load|(?:Loading|Loaded)\b[^\n]*\.env|\.env environment variables",
    re.IGNORECASE,
)


def _is_dotenv_banner(line: str) -> bool:
    """Return True for a collapsible dotenv loading / exported / skipped banner.

    Diagnostic and error lines are never banners; they fall through to be kept
    verbatim by the caller.
    """
    if _DOTENV_PARSE_WARN_RE.search(line) or _ERROR_SIGNAL_RE.search(line):
        return False
    return bool(
        _DOTENV_EXPORT_COUNT_RE.search(line)
        or _DOTENV_SKIPPED_RE.search(line)
        or _DOTENV_PLAIN_LOAD_RE.search(line)
    )


class DotenvFilter(Filter):
    """Compress dotenv / python-dotenv / dotenv-cli loading banners.

    Tools that hydrate the environment from a ``.env`` file emit chatty
    loading banners with no actionable content::

        [dotenv] Loading .env
        [dotenv] Exported 23 variables
        [dotenv] Skipped 2 variables (already set)

    or, from python-dotenv / pipenv::

        Loading .env environment variables...
        Loaded variables from .env

    Compression model:

    * **Collapse** two or more loading / ``Exported N variables`` /
      ``Skipped N variables`` banner lines into a single
      ``[dotenv] loaded N vars`` summary (``N`` is the exported/loaded tally;
      skipped counts are excluded).  When no count is present the summary
      degrades to ``[dotenv] loaded .env``.
    * **Keep** ``python-dotenv could not parse …`` parse warnings and their
      indented ``Path:`` / ``Line:`` continuation lines verbatim — they are
      actionable.
    * **Pass through** unchanged when there is at most one banner line (a lone
      ``Loading environment from .env`` message has nothing to collapse).

    Dispatched on the ``dotenv`` binary (python-dotenv CLI / npm ``dotenv-cli``);
    that binary is disjoint from every other filter so its registry position is
    cosmetic.
    """

    name = "dotenv"
    binaries = frozenset(["dotenv"])

    def compress(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        merged = self._combine_output(stdout, stderr)
        lines = merged.split("\n")
        banner_idx = {i for i, ln in enumerate(lines) if _is_dotenv_banner(ln)}
        # Nothing to collapse: single-line / no-banner messages pass through.
        if len(banner_idx) < 2:
            return self._finalize(lines)
        kept: list[str] = []
        loaded_total = 0
        insert_pos: int | None = None
        for i, line in enumerate(lines):
            if i in banner_idx:
                if insert_pos is None:
                    insert_pos = len(kept)
                m = _DOTENV_EXPORT_COUNT_RE.search(line)
                if m:
                    loaded_total += int(m.group(1))
                continue
            kept.append(line)
        summary = (
            f"[dotenv] loaded {loaded_total} vars" if loaded_total else "[dotenv] loaded .env"
        )
        kept.insert(insert_pos if insert_pos is not None else 0, summary)
        return self._finalize(kept)


# --- env / printenv output collapsing ----------------------------------------

# Variables always kept verbatim regardless of count.
_ENV_KEEP_VARS: Final[frozenset[str]] = frozenset({
    "PATH", "PYTHONPATH", "VIRTUAL_ENV", "CONDA_DEFAULT_ENV", "CONDA_PREFIX",
    "NODE_ENV", "NODE_VERSION", "NODE_PATH",
    "GOPATH", "GOROOT", "GOBIN",
    "JAVA_HOME", "JAVA_OPTS",
    "CARGO_HOME", "RUSTUP_HOME", "RUST_LOG",
    "GEM_HOME", "BUNDLE_PATH",
    "HOME", "USER", "USERNAME", "LOGNAME", "SHELL", "PWD", "OLDPWD",
    "TERM", "LANG", "LC_ALL", "TZ",
    "VIRTUAL_ENV_PROMPT",
    "npm_config_prefix", "npm_config_cache",
})
# Prefixes: keep any var whose name starts with one of these.
_ENV_KEEP_PREFIXES: Final[tuple[str, ...]] = (
    "CLAUDE_", "TOKEN_GOAT_", "CI_", "GITHUB_", "GITLAB_", "CIRCLECI_",
    "AWS_", "GCP_", "AZURE_", "GOOGLE_",
    "PYTHON", "UV_", "PIP_",
    "CONDA_", "NPM_", "PNPM_", "YARN_",
    "DOCKER_", "KUBECONFIG", "KUBE_",
    "TF_", "PULUMI_",
    "JAVA_", "MAVEN_", "GRADLE_",
    "CARGO_", "RUSTUP_", "RUST_",
)
# Threshold: if total KEY=value lines is at or below this, pass through as-is.
_ENV_PASSTHROUGH_THRESHOLD: Final[int] = 20

_ENV_LINE_RE: Final[re.Pattern[str]] = re.compile(r"^([A-Za-z_][A-Za-z_0-9]*)=(.*)$")


class EnvFilter(Filter):
    """Compress ``env`` / ``printenv`` environment-variable dumps.

    Compression model:

    * **Pass through** short dumps (≤ ``_ENV_PASSTHROUGH_THRESHOLD`` vars).
    * **Keep** important variables verbatim: ``PATH``, ``VIRTUAL_ENV``,
      ``NODE_ENV``, ``GOPATH``, ``JAVA_HOME``, and similar dev-environment
      sentinels.  Also keeps any variable whose name starts with a recognised
      tooling prefix (``GITHUB_``, ``AWS_``, ``TF_``, etc.).
    * **Suppress** remaining variables and emit a count summary.
    * **Keep** any non-assignment line verbatim (error output, etc.).
    """

    name = "env"
    binaries = frozenset(["env", "printenv"])

    def compress(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        merged = self._combine_output(stdout, stderr)
        lines = merged.splitlines()

        # Count total KEY=value lines to decide whether to compress.
        total_vars = sum(1 for ln in lines if _ENV_LINE_RE.match(ln))
        if total_vars <= _ENV_PASSTHROUGH_THRESHOLD:
            return merged

        kept: list[str] = []
        suppressed = 0

        for line in lines:
            m = _ENV_LINE_RE.match(line)
            if not m:
                # Non-assignment lines (errors, blank lines, etc.) — keep verbatim.
                kept.append(line)
                continue
            var_name = m.group(1)
            if var_name in _ENV_KEEP_VARS or any(
                var_name.startswith(p) for p in _ENV_KEEP_PREFIXES
            ):
                kept.append(line)
            else:
                suppressed += 1

        if suppressed:
            kept.append(
                f"[token-goat: {suppressed} env vars suppressed"
                f" ({total_vars} total) — run `env | grep NAME` to inspect]"
            )

        return self._finalize(kept)


# --- JSON array deduplication / truncation -----------------------------------

_JSON_ARRAY_MAX_ITEMS = 50


class JsonArrayFilter(Filter):
    """Compress JSON array output (e.g. ``npm ls --json``, ``gh api``, ``kubectl … -o json``).

    Compression model:

    * **Non-array / invalid JSON** — passed through unchanged.
    * **Key-set deduplication** — objects sharing the same ``frozenset`` of
      top-level keys are collapsed; all but the first are dropped and a
      ``[... N duplicate objects with keys {k1, k2, …} omitted]`` line is
      appended per group.  Non-dict items are kept as-is.
    * **Truncation** — after deduplication, if the array still exceeds
      :data:`_JSON_ARRAY_MAX_ITEMS` items the excess is dropped and a
      ``[... N more items not shown]`` suffix is appended.
    * **Passthrough** — when nothing was changed (no dups, no truncation) the
      original text is returned byte-for-byte so downstream callers can detect
      zero savings.
    """

    name = "json_array"
    # "json" is the binary stem registered in bash_detect._BINARY_TO_FILTER;
    # content-based detection (stdout starts with '[') is the primary path.
    binaries: frozenset[str] = frozenset(["json"])

    def matches(self, argv: list[str]) -> bool:  # noqa: D102
        if not argv:
            return False
        return Path(argv[0]).stem.lower() in self.binaries

    def detect_from_command(self, cmd: str) -> bool:  # noqa: D102
        return False  # content-based only; the hook layer routes via detect()

    def compress(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        text = stdout if stdout.strip() else (stdout + stderr)
        stripped = text.strip()
        if not (stripped.startswith("[") and stripped.endswith("]")):
            return text
        try:
            data = _json.loads(stripped)
        except _json.JSONDecodeError:
            return text
        if not isinstance(data, list):
            return text

        # --- key-set deduplication (dicts only) ----------------------------
        seen: dict[frozenset[str], int] = {}  # keyset → first-index position
        kept: list[object] = []
        dup_counts: dict[frozenset[str], int] = {}
        for item in data:
            if isinstance(item, dict):
                ks = frozenset(item.keys())
                # Preserve objects whose values contain high-entropy tokens (UUIDs, hashes, JWTs).
                preserve = any(isinstance(v, str) and has_high_entropy_token(v) for v in item.values())
                if ks in seen and not preserve:
                    dup_counts[ks] = dup_counts.get(ks, 0) + 1
                else:
                    if ks not in seen:
                        seen[ks] = len(kept)
                    kept.append(item)
            else:
                kept.append(item)
        changed = bool(dup_counts)

        # --- truncation ----------------------------------------------------
        suffix_lines: list[str] = []
        if dup_counts:
            for ks, n in dup_counts.items():
                keys_repr = ", ".join(sorted(ks))
                suffix_lines.append(f"[... {n} duplicate objects with keys {{{keys_repr}}} omitted]")
        if len(kept) > _JSON_ARRAY_MAX_ITEMS:
            extra = len(kept) - _JSON_ARRAY_MAX_ITEMS
            kept = kept[:_JSON_ARRAY_MAX_ITEMS]
            suffix_lines.append(f"[... {extra} more items not shown]")
            changed = True

        if not changed:
            return text

        parts = [_json.dumps(kept, indent=2)]
        parts.extend(suffix_lines)
        return "\n".join(parts)


# --- Binary inspection (xxd / hexdump / od) ----------------------------------

# Short dumps pass through unchanged (e.g. single-line `file` output leaking in).
_BIN_INSPECT_PASSTHROUGH: Final[int] = 4

# Magic-byte prefixes (lowercase hex, longest-match checked first).
_MAGIC_MAP: Final[tuple[tuple[str, str], ...]] = (
    ("89504e47", "PNG image"),
    ("ffd8ff",   "JPEG image"),
    ("25504446", "PDF document"),
    ("504b0304", "ZIP archive"),
    ("7f454c46", "ELF binary"),
    ("4d5a",     "Windows EXE/DLL"),
    ("cafebabe", "Java class file"),
    ("1f8b",     "gzip archive"),
    ("377abcaf", "7-zip archive"),
)

# Matches xxd ("OFFSET: XX XX ...") or hexdump -C ("OFFSET  XX XX ...").
_HEX_DUMP_LINE_RE: Final[re.Pattern[str]] = re.compile(
    r"^[0-9a-f]{4,}(?::\s+|\s{2,})([0-9a-f][0-9a-f\s]+)",
    re.IGNORECASE,
)


def _identify_hex_magic(first_line: str) -> tuple[str, str]:
    """Return (magic_hex, description) for the first hex-dump line.

    Falls back to ("", "unrecognised format") when the line cannot be parsed.
    """
    m = _HEX_DUMP_LINE_RE.match(first_line)
    if not m:
        return "", "unrecognised format"
    # Strip spaces from the data portion and normalise to lowercase.
    raw = m.group(1).replace(" ", "").lower()
    magic8 = raw[:8]
    if len(magic8) < 4:
        return "", "unrecognised format"
    for prefix, description in _MAGIC_MAP:
        if magic8.startswith(prefix):
            return magic8[:len(prefix)], description
    return magic8, "unknown binary type"


class BinaryInspectFilter(Filter):
    """Compress hex-dump output from ``xxd``, ``hexdump``, ``od``, and ``hd``.

    Compression model:

    * **Pass through** short output (≤ ``_BIN_INSPECT_PASSTHROUGH`` lines).
    * **Keep** the first 2 hex lines verbatim (shows magic bytes in context).
    * **Identify** the file type from the first 4 magic bytes.
    * **Replace** remaining lines with a single semantic summary line.
    """

    name = "xxd"
    binaries: frozenset[str] = frozenset(["xxd", "hexdump", "od", "hd"])

    def compress(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        merged = self._combine_output(stdout, stderr)
        lines = merged.splitlines()
        if len(lines) <= _BIN_INSPECT_PASSTHROUGH:
            return merged
        total = len(lines)
        magic_hex, description = _identify_hex_magic(lines[0].rstrip("\r\n"))
        if magic_hex:
            summary = (
                f"[token-goat: hex dump of {total} lines"
                f" — detected: {description} (magic: {magic_hex})]"
            )
        else:
            summary = f"[token-goat: hex dump of {total} lines — {description}]"
        kept: list[str] = list(lines[:2])
        kept.append(summary + "\n")
        return self._finalize(kept)


class FileTypeFilter(Filter):
    """Pass-through wrapper for the ``file`` command.

    ``file`` output is already semantic (e.g. "foo.png: PNG image, 800x600").
    This filter registers the binary so it is never accidentally routed to a
    generic handler.  Long batch runs (directory scans) are truncated to 20
    lines plus a count.
    """

    name = "file"
    binaries: frozenset[str] = frozenset(["file"])
    _BATCH_LIMIT: int = 20

    def compress(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        merged = self._combine_output(stdout, stderr)
        lines = merged.splitlines()
        if len(lines) <= self._BATCH_LIMIT:
            return merged
        remaining = len(lines) - self._BATCH_LIMIT
        kept = list(lines[:self._BATCH_LIMIT])
        kept.append(f"[token-goat: {remaining} more file entries truncated]\n")
        return self._finalize(kept)


# Regexes for severity-scored log line classification (SeverityLogFilter).
_LOG_LEVEL_RE: re.Pattern[str] = re.compile(
    r'\b(ERROR|FAIL(?:URE|ED)?|CRITICAL|EXCEPTION|FATAL)\b'
    r'|\[ERROR\]|\[CRITICAL\]|\[FATAL\]|level=(?:error|critical|fatal)',
    re.IGNORECASE,
)
_LOG_WARN_RE: re.Pattern[str] = re.compile(
    r'\b(WARN(?:ING)?)\b|\[WARN(?:ING)?\]|level=warn', re.IGNORECASE,
)
_LOG_INFO_RE: re.Pattern[str] = re.compile(
    r'\b(INFO)\b|\[INFO\]|level=info', re.IGNORECASE,
)
_LOG_DEBUG_RE: re.Pattern[str] = re.compile(
    r'\b(DEBUG|TRACE|VERBOSE)\b|\[DEBUG\]|\[TRACE\]|level=(?:debug|trace)', re.IGNORECASE,
)
# Combined keyword regex used for log-stream detection (30% threshold check).
_LOG_ANY_RE: re.Pattern[str] = re.compile(
    r'\b(?:ERROR|FAIL(?:URE|ED)?|CRITICAL|EXCEPTION|FATAL|WARN(?:ING)?|INFO|DEBUG|TRACE|VERBOSE)\b'
    r'|\[(?:ERROR|CRITICAL|FATAL|WARN(?:ING)?|INFO|DEBUG|TRACE)\]'
    r'|level=(?:error|critical|fatal|warn|info|debug|trace)',
    re.IGNORECASE,
)
# Stack-trace continuation lines kept unconditionally inside a trace window.
_TRACE_CONTINUATION_RE: re.Pattern[str] = re.compile(
    r'^\s+(?:at |File "|in |\w+Error:|\w+Exception:)'
    r'|^\s+\w+[\w.]+\(.*\)$'
    r'|^\s+\.{3}\s*\d+\s+more'
    r'|^Caused by:'
    r'|^During handling of the above exception',
)


def _score_log_line(line: str) -> float:
    """Return severity score for a single log line (0.0–1.0)."""
    if _LOG_LEVEL_RE.search(line):
        return 1.0
    if _LOG_WARN_RE.search(line):
        return 0.5
    if _LOG_INFO_RE.search(line):
        return 0.1
    if _LOG_DEBUG_RE.search(line):
        return 0.0
    return 0.0


def _compress_severity_log(text: str, context_n: int, threshold: float) -> str:
    """Apply severity-scored filtering to log text; return compressed output."""
    lines = text.splitlines()
    n = len(lines)
    scores = [_score_log_line(ln) for ln in lines]
    # First pass: identify primary-kept lines (high score or inside a trace window).
    primary: set[int] = set()
    in_trace = False
    for i, (ln, score) in enumerate(zip(lines, scores, strict=True)):
        if in_trace:
            if not ln.strip():
                in_trace = False
            elif _TRACE_CONTINUATION_RE.match(ln):
                primary.add(i)
            else:
                in_trace = False
                if score >= threshold:
                    primary.add(i)
                    if score >= 1.0:
                        in_trace = True
        else:
            if score >= threshold:
                primary.add(i)
                if score >= 1.0:
                    in_trace = True
    # Second pass: expand by context_n around every primary-kept line.
    expanded: set[int] = set()
    for idx in primary:
        for j in range(max(0, idx - context_n), min(n, idx + context_n + 1)):
            expanded.add(j)
    # Build output, inserting suppression sentinels at each gap.
    result: list[str] = []
    suppressed = 0
    for i, ln in enumerate(lines):
        if i in expanded:
            if suppressed > 0:
                result.append(f"[suppressed {suppressed} lines]")
                suppressed = 0
            result.append(ln)
        else:
            suppressed += 1
    if suppressed > 0:
        result.append(f"[suppressed {suppressed} lines]")
    return Filter._finalize(result)


class SeverityLogFilter(Filter):
    """Severity-scored compressor for structured log streams.

    Keeps every line scoring at or above *score_threshold* (ERROR/WARN by
    default), plus *context_lines* neighbours on each side.  Runs of
    lower-severity lines are replaced by ``[suppressed N lines]`` sentinels.
    Multi-line stack traces opened by an ERROR/FAIL line are preserved as a
    unit until a blank line or non-continuation line closes the window.
    """

    name = "severity_log"
    binaries: frozenset[str] = frozenset()

    @classmethod
    def detect(cls, stdout: str) -> bool:
        """Return True when stdout looks like a structured log stream.

        Requires at least 5 lines, with ≥30 % containing a log-level keyword.
        """
        lines = stdout.splitlines()
        if len(lines) < 5:
            return False
        keyword_count = sum(1 for ln in lines if _LOG_ANY_RE.search(ln))
        return keyword_count / len(lines) >= 0.30

    def detect_from_command(self, cmd: str) -> bool:  # noqa: D102
        return False  # content-based only; hook layer routes via detect()

    def matches(self, argv: list[str]) -> bool:  # noqa: D102
        return False  # content-based only; never claimed via binary dispatch

    def compress(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        combined = self._combine_output(stdout, stderr)
        if not self.detect(combined):
            return combined
        from . import config as _cfg_mod  # noqa: PLC0415
        cfg = _cfg_mod.load().bash_severity_log
        return _compress_severity_log(combined, cfg.context_lines, cfg.score_threshold)


class TailTruncFilter(Filter):
    """Safety-net catch-all: truncate unmatched outputs longer than 500 lines.

    Keeps the first 50 and last 50 lines with a suppressed-count marker in
    the middle.  Placed last in FILTERS so every more-specific filter wins;
    only activates when nothing else matched and the output is very long.
    Outputs of 500 lines or fewer pass through verbatim.
    """

    name = "tail-trunc"
    binaries: frozenset[str] = frozenset()

    def matches(self, argv: list[str]) -> bool:  # noqa: D102
        return True  # catch-all: always claim as last-resort fallback

    def compress(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        merged = self._combine_output(stdout, stderr)
        lines = merged.split("\n")
        if len(lines) <= 500:
            return merged
        suppressed = len(lines) - 100
        marker = f"[... {suppressed} lines suppressed — use TOKEN_GOAT_BASH_COMPRESS=0 to disable ...]"
        return "\n".join(lines[:50] + [marker] + lines[-50:])


_PS_MIN_LINES: Final[int] = 20
_PS_HEADER_KEYWORDS: Final[tuple[str, ...]] = ("PID", "COMMAND", "CMD", "IMAGE NAME", "%CPU", "UID")
_PS_TOP_PREFIXES: Final[tuple[str, ...]] = ("top -", "tasks:", "%cpu", "mib ", "kib ", "gib ")
_PS_DEV_SUBSTRINGS: Final[tuple[str, ...]] = (
    "python", "node", "uvicorn", "gunicorn", "django", "flask", "fastapi",
    "cargo", "rustc", "go ", "java", "ruby", "rails", "php", "postgres",
    "mysql", "redis", "nginx", "caddy", "docker", "kubectl", "npm",
    "pnpm", "yarn", "bun", "deno", "git", "ssh",
)


def _ps_keep_line(
    line: str,
    *,
    cpu_col: int | None,
    mem_col: int | None,
    cmd_start: int,
    is_tasklist: bool,
    current_user: str,
) -> bool:
    """Return True if a process line should be kept by PsFilter."""
    if is_tasklist:
        # tasklist has no user/cpu/mem columns by default; check whole line
        return any(sub in line.lower() for sub in _PS_DEV_SUBSTRINGS)
    cols = line.split()
    if not cols:
        return False
    # Keep user-owned processes (USER is col0 in ps aux/ps -ef)
    if current_user and cols[0].lower() == current_user:
        return True
    # Check command column for dev-relevant substrings
    cmd_str = " ".join(cols[cmd_start:]).lower() if len(cols) > cmd_start else line.lower()
    if any(sub in cmd_str for sub in _PS_DEV_SUBSTRINGS):
        return True
    # Check CPU/MEM resource thresholds when available
    if cpu_col is not None and mem_col is not None and len(cols) > max(cpu_col, mem_col):
        with contextlib.suppress(ValueError):
            if float(cols[cpu_col]) > 5.0 or float(cols[mem_col]) > 2.0:
                return True
    return False


class PsFilter(Filter):
    """Compress ps/top/tasklist process listing output.

    Keeps the header, dev-relevant processes, high-resource processes, and
    user-owned processes.  Drops kernel threads, system daemons, and idle
    processes.  Appends a ``[suppressed N system processes]`` sentinel line
    when any lines are dropped.  Passes through unchanged when the output is
    ≤ 20 lines or when nothing was suppressed.
    """

    name = "ps"
    binaries = frozenset(["ps", "top", "pstree", "tasklist"])

    @staticmethod
    def detect(stdout: str) -> bool:
        """Return True when stdout looks like ps, top, or tasklist tabular output."""
        for line in stdout.splitlines():
            stripped = line.strip()
            if not stripped:
                continue
            # top batch mode starts with a summary line
            if stripped.lower().startswith("top -"):
                return True
            # Column header contains known process-table keywords
            upper = stripped.upper()
            if any(kw in upper for kw in _PS_HEADER_KEYWORDS):
                return True
            break
        return False

    def compress(
        self, stdout: str, stderr: str, exit_code: int, argv: list[str],
    ) -> str:
        lines = stdout.splitlines()
        if len(lines) <= _PS_MIN_LINES:
            return stdout
        # Locate the column-header line (skip top's summary block)
        col_header_idx = -1
        for i, line in enumerate(lines):
            stripped = line.strip()
            if not stripped:
                continue
            lower = stripped.lower()
            # Skip top summary lines (top -, Tasks:, %Cpu, MiB, KiB, GiB)
            if any(lower.startswith(pfx) for pfx in _PS_TOP_PREFIXES):
                continue
            upper = stripped.upper()
            if any(kw in upper for kw in _PS_HEADER_KEYWORDS):
                col_header_idx = i
                break
        if col_header_idx == -1:
            return stdout
        header_upper = lines[col_header_idx].upper()
        is_tasklist = "IMAGE NAME" in header_upper
        # Dynamically locate %CPU/%MEM/COMMAND cols from header; ps aux=col2/3/10, top=col8/9/11, tasklist=n/a.
        header_tokens = lines[col_header_idx].split()
        cpu_col: int | None = next(
            (i for i, t in enumerate(header_tokens) if t.upper() == "%CPU"), None
        )
        mem_col: int | None = next(
            (i for i, t in enumerate(header_tokens) if t.upper() == "%MEM"), None
        )
        _cmd_col_names = frozenset(["COMMAND", "CMD"])
        cmd_start: int = next(
            (i for i, t in enumerate(header_tokens) if t.upper() in _cmd_col_names),
            10,  # fallback: ps aux default
        )
        current_user = (os.getenv("USERNAME") or os.getenv("USER") or "").lower()
        kept: list[str] = []
        suppressed_count = 0
        for i, line in enumerate(lines):
            # Keep all lines up to and including the column header
            if i <= col_header_idx:
                kept.append(line)
                continue
            stripped = line.strip()
            if not stripped:
                kept.append(line)
                continue
            # Keep tasklist separator lines (=== === ...)
            if is_tasklist and all(c in ("=", " ") for c in stripped):
                kept.append(line)
                continue
            if _ps_keep_line(
                line,
                cpu_col=cpu_col,
                mem_col=mem_col,
                cmd_start=cmd_start,
                is_tasklist=is_tasklist,
                current_user=current_user,
            ):
                kept.append(line)
            else:
                suppressed_count += 1
        if suppressed_count == 0:
            return stdout
        # Strip trailing blank lines before appending sentinel
        while kept and not kept[-1].strip():
            kept.pop()
        kept.append(f"[suppressed {suppressed_count} system processes]")
        return self._finalize(kept)


