# Shell redirect tokens: >, <, >>, 2>, 2>>, >&, &>, 1>, 1>>.  Compiled at
# module level because detect_from_command() is on the critical path (called
# for every pre-bash hook invocation).
_REDIRECT_TOKEN_RE: Final[re.Pattern[str]] = re.compile(
    r"^(\d*)(>>?|<<?).*$|^&>$|^>&.*$"
)


def select_filter(argv: list[str]) -> Filter | None:
    """Return the first registered filter whose ``matches(argv)`` is True.

    Returns ``None`` when no filter applies, callers should NOT wrap such
    commands in the compression subprocess (the overhead would be pure cost).

    The argv is prefix-stripped first via :func:`_strip_prefixes` so
    ``sudo time python -m pytest`` resolves to a ``pytest`` filter.
    """
    if not argv:
        return None
    resolved = _strip_prefixes(argv)
    if not resolved:
        # Prefix-stripping consumed the entire argv (e.g. bare `env`, `env -0`).
        # Fall back to the first original token so standalone env-dump commands
        # like `env` and `env -0` can still be routed to a dedicated filter.
        # No other filter has `env` / `sudo` / `time` etc. in their binaries,
        # so this fallback is safe: it only fires when a filter explicitly opts
        # in by listing a passthrough-prefix binary name.
        resolved = argv[:1]
        if not resolved:
            return None
    for f in FILTERS:
        try:
            if f.matches(resolved):
                return f
        except Exception:  # noqa: BLE001, never let a custom filter break dispatch
            _LOG.exception("filter %s raised during matches()", f.name)
    return None


def detect_from_command(command: str) -> tuple[Filter, list[str]] | None:
    """Parse a shell command string and return ``(filter, argv)`` or ``None``.

    Convenience wrapper for the hook layer: the hook receives one string from
    the harness, and dispatch needs both the filter and the argv (so the
    filter can inspect subcommands).  Returns ``None`` when:

    * the command exceeds 64 KiB (defensive against crafted payloads),
    * ``shlex.split`` fails (unbalanced quotes: leave it alone),
    * the command is empty after prefix stripping,
    * no filter matches.
    """
    if not command or len(command) > 65_536:
        return None
    # Reject commands that contain unquoted shell control operators — those
    # cannot be safely wrapped because the wrapper only intercepts a single
    # command, not a pipeline or sequence.  We split first so that operators
    # inside quoted arguments (e.g. pytest -k "count > 0") are NOT mistaken for
    # shell redirects.  Operators that must appear unquoted to have shell
    # meaning are checked against the raw string for the ones that shlex cannot
    # hide (pipe, command substitution, semicolon, logical AND/OR) and against
    # individual argv tokens for redirection (> < >> 2> >&).
    #
    # Raw-string checks: these operators can never appear as bare tokens AND
    # be "just part of an argument" in normal shell usage, so checking the raw
    # string is safe for them.
    if any(op in command for op in ("&&", "||", "$(", "`")):
        return None
    # Pipe and semicolon: a lone | or ; in the raw string signals a pipeline /
    # command list.  Quoted occurrences are extremely rare in practice and not
    # worth the complexity of a post-split check.
    if "|" in command or ";" in command:
        return None
    try:
        argv = shlex.split(command, posix=True)
    except ValueError:
        return None
    # Post-split redirect check: after shlex removes quotes, a bare > or < token
    # means shell redirect.  Inside quotes (e.g. -k "a > b") shlex folds the >
    # into the surrounding token, so it won't appear as a standalone element.
    # Common redirect forms: >, <, >>, 2>, 2>>, >&, &>, 1>, 1>>, /dev/null sinks.
    if any(_REDIRECT_TOKEN_RE.match(tok) for tok in argv):
        return None
    filter_ = select_filter(argv)
    if filter_ is None:
        return None
    return filter_, _strip_prefixes(argv)


_COMPOUND_AND_RE: Final[re.Pattern[str]] = re.compile(r"\s*&&\s*")


def _detect_single_segment(segment: str) -> tuple[Filter, list[str]] | None:
    """Like detect_from_command but for a single &&-split segment (no compound guard).

    Callers guarantee the segment was obtained by splitting on ``&&`` and
    contains no further compound operators.  Still rejects ``||``, ``|``,
    ``;``, ``$()``, and backtick substitution inside the segment.
    """
    segment = segment.strip()
    if not segment or len(segment) > 65_536:
        return None
    if any(op in segment for op in ("||", "$(", "`")):
        return None
    if "|" in segment or ";" in segment:
        return None
    try:
        argv = shlex.split(segment, posix=True)
    except ValueError:
        return None
    if any(_REDIRECT_TOKEN_RE.match(tok) for tok in argv):
        return None
    filter_ = select_filter(argv)
    if filter_ is None:
        return None
    return filter_, _strip_prefixes(argv)


def try_wrap_compound_segments(
    command: str,
    *,
    wrapper_args: Callable[[str, str], str | None],
) -> str | None:
    """Wrap each ``&&``-joined segment of a compound command independently.

    For a command like ``git diff && git log --oneline -5``, each segment is
    individually recognised and rewritten through the compression wrapper so
    the full compound still executes but its output lands compressed in context.

    ``wrapper_args(filter_name, segment)`` returns the wrapped command string
    for one segment, or ``None`` to leave that segment unchanged (e.g. when the
    filter is disabled).

    Returns the rewritten compound command when at least one segment was
    wrapped, or ``None`` when the command is not a safe ``&&``-compound or no
    segment matched a filter.
    """
    if not command or "||" in command or "|" in command or ";" in command:
        return None
    if "$(" in command or "`" in command:
        return None
    if "&&" not in command:
        return None
    segments = [s.strip() for s in _COMPOUND_AND_RE.split(command)]
    if not (2 <= len(segments) <= 8):
        return None
    wrapped_segments: list[str] = []
    any_wrapped = False
    for seg in segments:
        if not seg:
            return None  # empty segment (e.g. trailing &&) — bail
        detected = _detect_single_segment(seg)
        if detected is not None:
            filter_, _ = detected
            wrapped = wrapper_args(filter_.name, seg)
            if wrapped is not None:
                wrapped_segments.append(wrapped)
                any_wrapped = True
                continue
        wrapped_segments.append(seg)
    if not any_wrapped:
        return None
    return " && ".join(wrapped_segments)


def compress_output(
    filter_: Filter,
    stdout: str,
    stderr: str,
    exit_code: int,
    argv: list[str],
    *,
    max_lines: int = DEFAULT_MAX_LINES,
    max_bytes: int = DEFAULT_MAX_BYTES,
    compression_profile: str = "balanced",
) -> CompressedOutput:
    """Run *filter_* over the captured output and return a :class:`CompressedOutput`.

    This is the canonical entry point for the wrapper subprocess.  Always
    succeeds (the filter's own :meth:`apply` catches exceptions and falls back
    to a head/tail truncation).

    Args:
        filter_: The :class:`Filter` instance to apply.
        stdout: Captured standard output from the command.
        stderr: Captured standard error from the command.
        exit_code: Exit code of the wrapped command.
        argv: Parsed argv of the original command.
        max_lines: Per-invocation line cap (overridden by *compression_profile*
            when the profile provides a tighter or looser cap).
        max_bytes: Per-invocation byte cap as a hard backstop.
        compression_profile: One of ``"aggressive"`` (50 lines, all filters),
            ``"balanced"`` (200 lines, all filters — the default),
            ``"minimal"`` (500 lines, skip dot-progress filtering).  Any other
            value is treated as ``"balanced"``.  The effective *max_lines* is
            ``min(max_lines, profile_cap)`` so the caller-supplied cap is still
            respected when it is tighter than the profile cap.
    """
    # Map profile → effective max_lines and skip_progress flag.
    _PROFILE_CAPS: dict[str, int] = {"aggressive": 50, "balanced": 200, "minimal": 500}
    effective_max_lines = _PROFILE_CAPS.get(compression_profile, 200)
    # Respect the explicit caller cap when it is tighter.
    if max_lines < effective_max_lines:
        effective_max_lines = max_lines
    skip_progress = compression_profile == "minimal"
    return filter_.apply(
        stdout, stderr, exit_code, argv,
        max_lines=effective_max_lines,
        max_bytes=max_bytes,
        skip_progress=skip_progress,
    )


def filter_by_name(name: str) -> Filter | None:
    """Look up a registered filter by its :attr:`Filter.name`.

    Used when the hook layer has already detected the filter and the wrapper
    just needs to reconstruct it from a CLI flag.  Returns ``None`` for
    unknown names; the wrapper should then fall back to ``select_filter``.
    """
    for f in FILTERS:
        if f.name == name:
            return f
    return None


# ── Jest / Vitest post-bash detection helpers ─────────────────────────────────
# Module-level functions for the post-bash hook that detect and compress
# jest/vitest verbose output after command execution.  Complement the pre-bash
# JestFilter / VitestFilter which handle direct jest/mocha/vitest binaries.
# These helpers extend coverage to ``npm test``, ``npx jest``, ``yarn test``,
# and ``pnpm test`` invocations by matching on output shape, not just argv.

_JEST_NPM_CMD_RE: Final[re.Pattern[str]] = re.compile(
    r"\b(?:test|jest|vitest)\b", re.IGNORECASE,
)
# Per-test ✓ tick lines under a PASS suite block (indented 2+ spaces).
_JEST_PASS_TICK_RE: Final[re.Pattern[str]] = re.compile(r"^\s{2,}[✓✔√]\s")
# Vitest file-level pass/fail lines (single leading space, for post-bash use).
_VT_FILE_PASS_RE: Final[re.Pattern[str]] = re.compile(r"^ ✓ ")
_VT_FILE_FAIL_RE: Final[re.Pattern[str]] = re.compile(r"^ [×✗✕✘] ")
# Word-only PASS/FAIL detection: excludes vitest Unicode symbols (×, ✗, etc.)
# that also appear in _JEST_FAIL_LINE_RE but belong to vitest, not jest.
_JEST_WORD_DETECT_RE: Final[re.Pattern[str]] = re.compile(r"^\s*(?:PASS|FAIL)\s+\S")


def _is_jest_cmd(argv: list[str]) -> bool:
    """Return True when argv looks like a jest/vitest invocation.

    Matches direct jest/vitest/react-scripts binaries and package-manager
    shims (``npx jest``, ``npm test``, ``yarn test``, ``pnpm test``).
    """
    if not argv:
        return False

    def _base(s: str) -> str:
        b = s.replace("\\", "/").rsplit("/", 1)[-1].lower()
        for ext in (".exe", ".cmd"):
            if b.endswith(ext):
                b = b[: -len(ext)]
                break
        return b

    base = _base(argv[0])
    if base in ("jest", "vitest", "react-scripts"):
        return True
    if base in ("npx", "yarn", "pnpm", "npm") and len(argv) >= 2:
        # Skip leading flags (e.g. npx --yes jest, yarn --cwd ./app jest)
        for tok in argv[1:]:
            if tok.startswith("-"):
                continue
            return bool(_JEST_NPM_CMD_RE.search(tok))
    return False


def _has_jest_output(stdout: str) -> bool:
    """Return True when stdout contains jest-style PASS/FAIL suite headers.

    Uses a word-only pattern (PASS/FAIL ASCII) rather than the shared
    _JEST_FAIL_LINE_RE so that vitest Unicode symbols (×, ✗) do not trigger
    a false positive here.  _has_vitest_output handles those separately.
    """
    return any(_JEST_WORD_DETECT_RE.match(ln) for ln in stdout.splitlines())


def _has_vitest_output(stdout: str) -> bool:
    """Return True when stdout contains vitest-style file-level ✓ / × headers."""
    return any(
        _VT_FILE_PASS_RE.match(ln) or _VT_FILE_FAIL_RE.match(ln)
        for ln in stdout.splitlines()
    )


def compress_jest_output(stdout: str) -> tuple[str, int, int]:
    """Compress jest/vitest verbose output for the post-bash hook.

    Returns ``(compressed_text, pass_count, fail_count)``.  Suppresses PASS
    suite headers and their per-test ✓ children; keeps FAIL blocks and the
    summary block intact.  This is a lighter-weight variant of
    :class:`JestFilter` (no stderr merging, no console-block collapsing)
    designed for the post-bash hook code path.
    """
    lines = stdout.splitlines(keepends=True)
    out: list[str] = []
    pass_count = 0
    fail_count = 0
    in_pass_block = False

    is_vitest = _has_vitest_output(stdout) and not _has_jest_output(stdout)

    if is_vitest:
        # Vitest: suppress file-level ✓ lines and their per-test ✓ children;
        # keep × lines, failure detail blocks, and summary.
        in_pass_file = False
        for line in lines:
            if _VT_FILE_PASS_RE.match(line):
                pass_count += 1
                in_pass_file = True
                continue
            if _VT_FILE_FAIL_RE.match(line):
                fail_count += 1
                in_pass_file = False
                out.append(line)
                continue
            if in_pass_file and _VITEST_TEST_PASS_RE.match(line):
                continue  # per-test ✓ under a passing file block
            if in_pass_file and not line.startswith((" ", "\t")):
                in_pass_file = False
            out.append(line)
    else:
        # Jest: suppress PASS headers and their indented ✓ children.
        for line in lines:
            if _JEST_PASS_LINE_RE.match(line):
                pass_count += 1
                in_pass_block = True
                continue
            if _JEST_FAIL_LINE_RE.match(line):
                fail_count += 1
                in_pass_block = False
                out.append(line)
                continue
            if in_pass_block:
                if line.startswith((" ", "\t")):
                    if _JEST_PASS_TICK_RE.match(line):
                        continue
                    out.append(line)
                    continue
                in_pass_block = False
            out.append(line)

    return "".join(out), pass_count, fail_count


# ── curl verbose output ──────────────────────────────────────────────────────
_CURL_REQUEST_LINE_RE: Final[re.Pattern[str]] = re.compile(
    r"^> (?:GET|POST|PUT|PATCH|DELETE|HEAD|OPTIONS|TRACE) "
)
_CURL_V_STATUS_RE: Final[re.Pattern[str]] = re.compile(
    r"^< HTTP/[12](?:\.\d)? \d{3}"
)
_CURL_CONTENT_TYPE_RE: Final[re.Pattern[str]] = re.compile(
    r"^< [Cc]ontent-[Tt]ype:", re.IGNORECASE
)
_CURL_VERBOSE_PROGRESS_RE: Final[re.Pattern[str]] = re.compile(
    r"^\s*(?:%\s+Total\s+%\s+Received"   # header line
    r"|Dload\s+Upload\s+Total"               # subheader line
    r"|\d[\d ]+(?:--:--:--|\d:\d+:\d+))"  # numeric data lines
)


def _is_curl_verbose_cmd(argv: list[str]) -> bool:
    """Return True when argv is a curl command with verbose flag."""
    if not argv:
        return False

    def _base(s: str) -> str:
        b = s.replace("\\", "/").rsplit("/", 1)[-1].lower()
        for ext in (".exe", ".cmd"):
            if b.endswith(ext):
                b = b[: -len(ext)]
                break
        return b

    base = _base(argv[0])
    if base != "curl":
        return False
    args_str = " ".join(argv[1:])
    # -v, --verbose, or combined short flags containing v (e.g. -vL, -vsL)
    return bool(
        re.search(r"(?:^|\s)--verbose(?:\s|$)", args_str)
        or re.search(r"(?:^|\s)-[a-zA-Z]*v[a-zA-Z]*(?:\s|$)", args_str)
    )


def _has_curl_verbose_output(stdout: str) -> bool:
    """Return True when stdout contains curl verbose markers."""
    lines = stdout.splitlines()
    has_star = any(ln.startswith("* ") for ln in lines)
    has_req = any(ln.startswith("> ") for ln in lines)
    has_resp = any(ln.startswith("< ") for ln in lines)
    return has_star or (has_req and has_resp)


def compress_curl_verbose(stdout: str) -> tuple[str, int]:
    """Strip curl verbose noise, keeping request line, status, content-type, body.

    Returns (compressed_text, lines_removed).
    The response body (after the blank separator) is kept verbatim.
    """
    lines = stdout.splitlines(keepends=True)
    out: list[str] = []
    lines_removed = 0
    in_body = False
    found_request_line = False
    found_status = False
    found_content_type = False

    for line in lines:
        # Once we're in the body, keep everything.
        # A `* ` line while in body mode means curl is following a redirect —
        # reset so the next request/response cycle gets compressed normally.
        if in_body:
            if line.startswith("* "):
                in_body = False
                found_request_line = False
                found_status = False
                found_content_type = False
                lines_removed += 1
                continue
            out.append(line)
            continue

        # Bare `<` line = end of response headers, body follows.
        # Bare `>` line = end of request headers (response headers come next, not body).
        # Empty line = body content (no prefix markers).
        stripped = line.rstrip("\r\n")
        if stripped == "<":
            out.append(line)
            in_body = True
            continue
        if stripped == ">":
            # End-of-request-headers separator; emit and continue to response headers.
            out.append(line)
            continue
        if stripped == "":
            out.append(line)
            continue

        # `* ` lines (connection/TLS info) — always suppress
        if line.startswith("* "):
            lines_removed += 1
            continue

        # `> ` lines (request headers) — keep only the request line
        if line.startswith("> "):
            if not found_request_line and _CURL_REQUEST_LINE_RE.match(line):
                found_request_line = True
                out.append(line)
            else:
                lines_removed += 1
            continue

        # `< ` lines (response headers) — keep status + content-type only
        if line.startswith("< "):
            if not found_status and _CURL_V_STATUS_RE.match(line):
                found_status = True
                out.append(line)
            elif not found_content_type and _CURL_CONTENT_TYPE_RE.match(line):
                found_content_type = True
                out.append(line)
            else:
                lines_removed += 1
            continue

        # curl progress meter lines — suppress
        if _CURL_VERBOSE_PROGRESS_RE.match(line):
            lines_removed += 1
            continue

        # Everything else (body content or plain text) — keep
        out.append(line)

    return "".join(out), lines_removed


# ── docker build output ──────────────────────────────────────────────────────
_DOCKER_BUILD_STEP_RE: Final[re.Pattern[str]] = re.compile(r"^Step \d+/\d+ : ", re.MULTILINE)
_DOCKER_ARROW_RE: Final[re.Pattern[str]] = re.compile(r"^ --->")
_DOCKER_SUPPRESS_ARROW_RE: Final[re.Pattern[str]] = re.compile(
    r"^ ---> (?:Using cache|Running in [0-9a-f]+|[0-9a-f]{12,})\s*$"
)
_DOCKER_BUILDKIT_STEP_RE: Final[re.Pattern[str]] = re.compile(r"^ => (?:CACHED )?\[")
_DOCKER_BUILDKIT_SUBSTEP_RE: Final[re.Pattern[str]] = re.compile(r"^ => => ")
_DOCKER_BUILDKIT_SUMMARY_RE: Final[re.Pattern[str]] = re.compile(r"^\[\+\] Building", re.MULTILINE)
_DOCKER_BUILD_SUCCESS_RE: Final[re.Pattern[str]] = re.compile(
    r"^(?:Successfully (?:built|tagged)|FINISHED)"
)
_DOCKER_SUPPRESS_MISC_RE: Final[re.Pattern[str]] = re.compile(
    r"^(?:Sending build context to Docker daemon|Removing intermediate container)"
)


def _is_docker_build_cmd(argv: list[str]) -> bool:
    """Return True when argv is a docker build / buildx build invocation."""
    if not argv:
        return False

    def _base(s: str) -> str:
        return Path(s).stem.lower()

    base = _base(argv[0])
    if base not in ("docker", "docker-compose", "docker-buildx"):
        return False
    args = [a.lower() for a in argv[1:]]
    return "build" in args


def _has_docker_build_output(stdout: str) -> bool:
    """Return True when stdout looks like docker build output."""
    return bool(
        _DOCKER_BUILD_STEP_RE.search(stdout)
        or _DOCKER_BUILDKIT_SUMMARY_RE.search(stdout)
    )


def compress_docker_build(stdout: str) -> tuple[str, int]:
    """Compress docker build output, keeping step headers and errors.

    Returns (compressed_text, lines_removed).
    """
    lines = stdout.splitlines(keepends=True)
    out: list[str] = []
    lines_removed = 0
    in_run_step = False  # True when inside a RUN step (keep its output)

    for line in lines:
        stripped = line.rstrip("\r\n")

        # Suppress misc noise at the start
        if _DOCKER_SUPPRESS_MISC_RE.match(stripped):
            lines_removed += 1
            continue

        # Classic format: Step N/M
        if _DOCKER_BUILD_STEP_RE.match(stripped):
            in_run_step = "RUN " in stripped.upper() or stripped.upper().endswith(" RUN")
            out.append(line)
            continue

        # Classic format: ---> lines to suppress (Using cache, Running in, bare hash)
        if _DOCKER_SUPPRESS_ARROW_RE.match(stripped):
            lines_removed += 1
            continue

        # Classic format: keep other ---> lines (e.g., error context)
        if _DOCKER_ARROW_RE.match(stripped):
            out.append(line)
            continue

        # BuildKit summary [+] Building
        if _DOCKER_BUILDKIT_SUMMARY_RE.match(stripped):
            out.append(line)
            continue

        # BuildKit step lines: keep [N/M] and CACHED [N/M]
        if _DOCKER_BUILDKIT_STEP_RE.match(stripped):
            out.append(line)
            continue

        # BuildKit sub-step lines: suppress
        if _DOCKER_BUILDKIT_SUBSTEP_RE.match(stripped):
            lines_removed += 1
            continue

        # Success/FINISHED lines
        if _DOCKER_BUILD_SUCCESS_RE.match(stripped):
            out.append(line)
            continue

        # Error / failure lines — always keep
        lower = stripped.lower()
        if "error" in lower or "failed" in lower or "fail" in lower:
            out.append(line)
            continue

        # Non-step lines: keep if inside a RUN step (command output), suppress otherwise
        if in_run_step:
            out.append(line)
        else:
            lines_removed += 1

    return "".join(out), lines_removed
